(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,267976,e=>{"use strict";let o=[{id:"scn-a1-cafe-001",level:"A1",situation:"food",title:{en:"Ordering at a cafe",ko:"카페에서 주문하기"},context:{en:"You walk into a cafe and order a drink.",ko:"카페에 들어가 음료를 주문합니다."},turns:[{prompt:{en:"Hi! What can I get for you?",ko:"안녕하세요! 뭐 드릴까요?"},template:"Can I get a {0}, please?",blanks:[[{en:"coffee",ko:"커피",note:"가장 무난한 기본 음료"},{en:"latte",ko:"라떼",note:"우유 들어간 부드러운 커피"},{en:"green tea",ko:"녹차",note:"커피 말고 차를 원할 때"}]],example:{en:"Can I get a coffee, please?",ko:"커피 한 잔 주시겠어요?"}},{prompt:{en:"Sure. For here or to go?",ko:"네. 드시고 가세요, 가져가세요?"},template:"{0}, please.",blanks:[[{en:"For here",ko:"여기서 먹을게요",note:"매장에 앉아서 먹을 때"},{en:"To go",ko:"가져갈게요",note:"포장해서 가져갈 때"}]],example:{en:"For here, please.",ko:"여기서 먹을게요."}},{prompt:{en:"That'll be 4 dollars.",ko:"4달러입니다."},template:"Here you are. {0}!",blanks:[[{en:"Thank you",ko:"감사합니다",note:"또박또박 정중하게 감사"},{en:"Thanks",ko:"고마워요",note:"짧고 가벼운 일상 감사"}]],example:{en:"Here you are. Thank you!",ko:"여기 있어요. 감사합니다!"}}]},{id:"scn-a1-greetings-001",level:"A1",situation:"greetings",title:{en:"Meeting someone new",ko:"처음 만난 사람과 인사"},context:{en:"You meet a new classmate for the first time.",ko:"새 반 친구를 처음 만납니다."},turns:[{prompt:{en:"Hi, I'm Mina. What's your name?",ko:"안녕, 난 미나야. 네 이름은?"},template:"Hi Mina, I'm {0}. Nice to meet you!",blanks:[[{en:"Jun",ko:"준",note:"자기 이름 자리 (예: 준)"},{en:"Sora",ko:"소라",note:"자기 이름 자리 (예: 소라)"}]],example:{en:"Hi Mina, I'm Jun. Nice to meet you!",ko:"안녕 미나, 난 준이야. 만나서 반가워!"}},{prompt:{en:"Where are you from?",ko:"어디서 왔어?"},template:"I'm from {0}.",blanks:[[{en:"Korea",ko:"한국",note:"나라 이름으로 답할 때"},{en:"Seoul",ko:"서울",note:"사는 도시 이름 (서울)"},{en:"Busan",ko:"부산",note:"사는 도시 이름 (부산)"}]],example:{en:"I'm from Korea.",ko:"난 한국에서 왔어."}},{prompt:{en:"Cool! See you in class.",ko:"멋지다! 수업에서 봐."},template:"See you {0}!",blanks:[[{en:"later",ko:"나중에",note:"언제일지 정하지 않은 편한 작별"},{en:"soon",ko:"곧",note:"머지않아 또 보자는 느낌"}]],example:{en:"See you later!",ko:"나중에 봐!"}}]},{id:"scn-a2-restaurant-001",level:"A2",situation:"restaurant",title:{en:"Dinner at a restaurant",ko:"식당에서 저녁 식사"},context:{en:"You arrive at a restaurant, get a table, order food, and ask for the bill.",ko:"식당에 도착해 자리를 안내받고, 음식을 주문한 뒤 계산을 요청합니다."},turns:[{prompt:{en:"Good evening! How many people?",ko:"안녕하세요! 몇 분이세요?"},template:"A table for {0}, please.",blanks:[[{en:"two",ko:"두 명",note:"둘이 갈 때"},{en:"three",ko:"세 명",note:"셋이 갈 때"},{en:"four",ko:"네 명",note:"넷이 갈 때"}]],example:{en:"A table for two, please.",ko:"두 명 자리 부탁해요."}},{prompt:{en:"Here's the menu. What would you like to order?",ko:"메뉴 여기 있습니다. 무엇을 주문하시겠어요?"},template:"I'll have the {0}, please.",blanks:[[{en:"steak",ko:"스테이크",note:"든든한 고기 요리"},{en:"pasta",ko:"파스타",note:"가볍게 즐기는 면 요리"},{en:"grilled chicken",ko:"구운 치킨",note:"담백한 닭고기 요리"}]],example:{en:"I'll have the steak, please.",ko:"스테이크로 할게요."}},{prompt:{en:"Anything to drink with that?",ko:"음료도 함께 하시겠어요?"},template:"Yes, a {0}, please.",blanks:[[{en:"glass of water",ko:"물 한 잔",note:"무난하고 부담 없는 선택"},{en:"Coke",ko:"콜라",note:"달콤한 탄산음료"},{en:"glass of wine",ko:"와인 한 잔",note:"분위기를 내는 술 한 잔"}]],example:{en:"Yes, a glass of water, please.",ko:"네, 물 한 잔 주세요."}},{prompt:{en:"Did you enjoy your meal?",ko:"식사 맛있게 하셨어요?"},template:"It was {0}. Can I have the {1}, please?",blanks:[[{en:"great",ko:"훌륭했어요",note:"전반적으로 만족스러웠다는 느낌"},{en:"delicious",ko:"맛있었어요",note:"음식 맛을 콕 집어 칭찬"}],[{en:"bill",ko:"계산서",note:"영국식에서 흔한 표현"},{en:"check",ko:"계산서",note:"미국식에서 흔한 표현"}]],example:{en:"It was great. Can I have the bill, please?",ko:"훌륭했어요. 계산서 주시겠어요?"}}]},{id:"scn-a2-hotel-001",level:"A2",situation:"hotel",title:{en:"Checking into a hotel",ko:"호텔 체크인하기"},context:{en:"You arrive at a hotel, check in, ask about breakfast, and get your room key.",ko:"호텔에 도착해 체크인하고, 조식을 물어본 뒤 객실 키를 받습니다."},turns:[{prompt:{en:"Welcome! Do you have a reservation?",ko:"어서 오세요! 예약하셨나요?"},template:"Yes, I have a reservation under {0}.",blanks:[[{en:"Kim",ko:"김",note:"예약자 성이 김 씨일 때"},{en:"Lee",ko:"이",note:"예약자 성이 이 씨일 때"},{en:"Park",ko:"박",note:"예약자 성이 박 씨일 때"}]],example:{en:"Yes, I have a reservation under Kim.",ko:"네, 김으로 예약했어요."}},{prompt:{en:"Great. How many nights will you stay?",ko:"좋습니다. 몇 박 묵으시나요?"},template:"For {0} nights, please.",blanks:[[{en:"two",ko:"이",note:"2박 묵을 때"},{en:"three",ko:"삼",note:"3박 묵을 때"},{en:"five",ko:"오",note:"5박 묵을 때"}]],example:{en:"For two nights, please.",ko:"2박이요."}},{prompt:{en:"Is there anything I can help you with?",ko:"도와드릴 일이 있으실까요?"},template:"What time is {0}?",blanks:[[{en:"breakfast",ko:"조식",note:"아침 식사 시간을 물을 때"},{en:"check-out",ko:"체크아웃",note:"퇴실 시간을 물을 때"}]],example:{en:"What time is breakfast?",ko:"조식은 몇 시인가요?"}},{prompt:{en:"Here is your room key. Enjoy your stay!",ko:"객실 키 여기 있습니다. 즐거운 시간 보내세요!"},template:"Thank you. Which {0} is the room on?",blanks:[[{en:"floor",ko:"층",note:"몇 층인지 물을 때 자연스러운 표현"},{en:"side",ko:"쪽",note:"건물의 어느 편(좌/우)에 있는지 물을 때"}]],example:{en:"Thank you. Which floor is the room on?",ko:"감사합니다. 객실은 몇 층인가요?"}}]},{id:"scn-a2-shopping-001",level:"A2",situation:"shopping",title:{en:"Buying clothes",ko:"옷 사기"},context:{en:"You are in a clothing store looking for a shirt, trying it on, and paying.",ko:"옷 가게에서 셔츠를 찾고, 입어본 뒤 결제합니다."},turns:[{prompt:{en:"Hi, can I help you find something?",ko:"안녕하세요, 찾으시는 거 있으세요?"},template:"Yes, I'm looking for a {0}.",blanks:[[{en:"shirt",ko:"셔츠",note:"상의 셔츠를 찾을 때"},{en:"jacket",ko:"재킷",note:"겉옷을 찾을 때"},{en:"pair of jeans",ko:"청바지",note:"바지라 a pair of를 쓸 때"}]],example:{en:"Yes, I'm looking for a shirt.",ko:"네, 셔츠를 찾고 있어요."}},{prompt:{en:"Sure. What size do you need?",ko:"네. 어떤 사이즈가 필요하세요?"},template:"I think I need a {0} one.",blanks:[[{en:"small",ko:"스몰",note:"작은 사이즈가 필요할 때"},{en:"medium",ko:"미디엄",note:"중간 사이즈가 필요할 때"},{en:"large",ko:"라지",note:"큰 사이즈가 필요할 때"}]],example:{en:"I think I need a medium one.",ko:"미디엄이 필요할 것 같아요."}},{prompt:{en:"Here you go. Would you like to try it on?",ko:"여기요. 입어보시겠어요?"},template:"Yes, where is the {0}?",blanks:[[{en:"fitting room",ko:"탈의실",note:"옷을 갈아입을 곳을 물을 때"},{en:"mirror",ko:"거울",note:"비춰볼 거울을 찾을 때"}]],example:{en:"Yes, where is the fitting room?",ko:"네, 탈의실은 어디예요?"}},{prompt:{en:"It looks great on you! Will you take it?",ko:"정말 잘 어울려요! 구매하시겠어요?"},template:"Yes, I'll take it. Can I pay by {0}?",blanks:[[{en:"card",ko:"카드",note:"신용·체크카드로 결제할 때"},{en:"cash",ko:"현금",note:"현금으로 결제할 때"}]],example:{en:"Yes, I'll take it. Can I pay by card?",ko:"네, 살게요. 카드로 결제해도 되나요?"}}]},{id:"scn-a2-doctor-001",level:"A2",situation:"doctor",title:{en:"Visiting the doctor",ko:"병원 진료받기"},context:{en:"You visit a doctor because you feel sick and describe your symptoms.",ko:"몸이 아파서 병원에 가 증상을 설명합니다."},turns:[{prompt:{en:"Hello, what seems to be the problem?",ko:"안녕하세요, 어디가 안 좋으세요?"},template:"I have a {0}.",blanks:[[{en:"headache",ko:"두통",note:"머리가 아플 때"},{en:"sore throat",ko:"인후통",note:"목이 따갑고 아플 때"},{en:"fever",ko:"열",note:"몸에 열이 날 때"}]],example:{en:"I have a headache.",ko:"머리가 아파요."}},{prompt:{en:"I see. How long have you felt like this?",ko:"그렇군요. 언제부터 그러셨어요?"},template:"Since {0}.",blanks:[[{en:"yesterday",ko:"어제",note:"하루 전부터 아팠을 때"},{en:"two days ago",ko:"이틀 전",note:"이틀 전부터 아팠을 때"},{en:"this morning",ko:"오늘 아침",note:"오늘 막 시작됐을 때"}]],example:{en:"Since yesterday.",ko:"어제부터요."}},{prompt:{en:"Take this medicine twice a day. Do you have any allergies?",ko:"이 약을 하루에 두 번 드세요. 알레르기 있으세요?"},template:"No, I don't. How long should I {0} it?",blanks:[[{en:"take",ko:"복용해야",note:"먹는 약에 쓰는 동사"},{en:"use",ko:"사용해야",note:"연고·물약 등 바르거나 쓸 때"}]],example:{en:"No, I don't. How long should I take it?",ko:"아니요, 없어요. 얼마나 복용해야 하나요?"}}]},{id:"scn-a2-phone-001",level:"A2",situation:"phone",title:{en:"Making a phone call",ko:"전화 통화하기"},context:{en:"You call a friend's home to ask if they can meet up later.",ko:"친구 집에 전화를 걸어 나중에 만날 수 있는지 물어봅니다."},turns:[{prompt:{en:"Hello? Who's calling?",ko:"여보세요? 누구세요?"},template:"Hi, this is {0}. Is Sam there?",blanks:[[{en:"Jun",ko:"준",note:"본인 이름이 준일 때"},{en:"Mina",ko:"미나",note:"본인 이름이 미나일 때"}]],example:{en:"Hi, this is Jun. Is Sam there?",ko:"안녕하세요, 저 준이에요. 샘 있나요?"}},{prompt:{en:"Just a moment. Sorry, he's not home right now.",ko:"잠시만요. 죄송한데 지금 집에 없어요."},template:"Oh, can I {0} a message?",blanks:[[{en:"leave",ko:"남겨도",note:"내가 메시지를 남길 때 쓰는 동사"},{en:"take",ko:"전해도",note:"메시지를 받아 전달한다는 뉘앙스"}]],example:{en:"Oh, can I leave a message?",ko:"아, 메시지를 남겨도 될까요?"}},{prompt:{en:"Of course. What would you like to say?",ko:"그럼요. 어떻게 전해드릴까요?"},template:"Please tell him to {0} me back tonight.",blanks:[[{en:"call",ko:"전화해",note:"직접 통화로 연락 달라 할 때"},{en:"text",ko:"문자해",note:"문자 메시지로 연락 달라 할 때"}]],example:{en:"Please tell him to call me back tonight.",ko:"오늘 밤에 저한테 전화해 달라고 전해주세요."}},{prompt:{en:"I'll let him know. Anything else?",ko:"전해드릴게요. 더 필요한 거 있으세요?"},template:"No, that's all. {0} very much!",blanks:[[{en:"Thank you",ko:"감사합니다",note:"조금 더 정중한 인사"},{en:"Thanks",ko:"고마워요",note:"가볍고 캐주얼한 인사"}]],example:{en:"No, that's all. Thank you very much!",ko:"아니요, 그게 다예요. 정말 감사합니다!"}}]},{id:"scn-b1-job-interview-001",level:"B1",situation:"job-interview",title:{en:"A job interview",ko:"취업 면접"},context:{en:"You are at an interview for a marketing position.",ko:"마케팅 직무 면접을 보고 있습니다."},turns:[{prompt:{en:"Thanks for coming in. Could you tell me a little about yourself?",ko:"와 주셔서 감사합니다. 본인에 대해 간단히 말씀해 주시겠어요?"},template:"Sure. I'm a {0} with about {1} of experience, and I really enjoy {2}.",blanks:[[{en:"marketer",ko:"마케터",note:"마케팅 직무를 밝힘"},{en:"designer",ko:"디자이너",note:"디자인 직무를 밝힘"},{en:"project manager",ko:"프로젝트 매니저",note:"관리 직무를 밝힘"}],[{en:"three years",ko:"3년",note:"비교적 짧은 경력"},{en:"five years",ko:"5년",note:"어느 정도 쌓인 경력"}],[{en:"working with teams",ko:"팀과 협업하는 것",note:"협업 성향을 어필"},{en:"solving problems",ko:"문제를 해결하는 것",note:"문제 해결력을 어필"}]],example:{en:"Sure. I'm a marketer with about three years of experience, and I really enjoy working with teams.",ko:"네. 저는 약 3년 경력의 마케터이고, 팀과 협업하는 것을 정말 좋아합니다."}},{prompt:{en:"Why do you want to work for our company?",ko:"왜 저희 회사에서 일하고 싶으신가요?"},template:"I'm interested because your company is known for {0}, and I'd love to {1}.",blanks:[[{en:"its creative culture",ko:"창의적인 문화",note:"조직 분위기를 칭찬"},{en:"strong teamwork",ko:"탄탄한 팀워크",note:"협업 강점을 칭찬"},{en:"innovative products",ko:"혁신적인 제품",note:"제품 경쟁력을 칭찬"}],[{en:"grow my skills here",ko:"여기서 제 역량을 키우다",note:"자기 성장에 초점"},{en:"contribute to that",ko:"거기에 기여하다",note:"회사에 보탬이 되겠다는 초점"}]],example:{en:"I'm interested because your company is known for its creative culture, and I'd love to grow my skills here.",ko:"귀사는 창의적인 문화로 잘 알려져 있어서 관심이 있고, 이곳에서 제 역량을 키우고 싶습니다."}},{prompt:{en:"What would you say is your biggest strength?",ko:"본인의 가장 큰 강점은 무엇이라고 생각하시나요?"},template:"I think my biggest strength is that I'm {0}, so I can usually {1} even when things get busy.",blanks:[[{en:"well organized",ko:"체계적인",note:"정리·관리 능력을 강조"},{en:"a good communicator",ko:"소통을 잘하는 사람",note:"대인 소통력을 강조"},{en:"very reliable",ko:"매우 믿음직한",note:"책임감·신뢰를 강조"}],[{en:"meet deadlines",ko:"마감을 지키다",note:"기한 엄수에 초점"},{en:"keep the team on track",ko:"팀을 제 궤도에 두다",note:"팀 전체를 챙긴다는 초점"}]],example:{en:"I think my biggest strength is that I'm well organized, so I can usually meet deadlines even when things get busy.",ko:"제 가장 큰 강점은 체계적이라는 점이어서, 바쁠 때에도 보통 마감을 지킬 수 있습니다."}},{prompt:{en:"Great. Do you have any questions for us?",ko:"좋습니다. 저희에게 궁금한 점이 있으신가요?"},template:"Yes, I'd like to know more about {0}. When can I expect to hear back about {1}?",blanks:[[{en:"the team I'd join",ko:"제가 합류할 팀",note:"함께 일할 팀을 궁금해함"},{en:"the daily responsibilities",ko:"일상적인 업무",note:"실제 업무 내용을 궁금해함"},{en:"opportunities to grow",ko:"성장 기회",note:"성장·발전 가능성을 궁금해함"}],[{en:"the next steps",ko:"다음 단계",note:"이후 절차를 부드럽게 물음"},{en:"your decision",ko:"결과",note:"합격 여부를 직접적으로 물음"}]],example:{en:"Yes, I'd like to know more about the team I'd join. When can I expect to hear back about the next steps?",ko:"네, 제가 합류할 팀에 대해 더 알고 싶습니다. 다음 단계에 대해서는 언제쯤 연락을 받을 수 있을까요?"}}]},{id:"scn-b1-travel-checkin-001",level:"B1",situation:"travel-checkin",title:{en:"Checking in at a hotel",ko:"호텔 체크인"},context:{en:"You arrive at a hotel and check in for your stay.",ko:"호텔에 도착해 숙박 체크인을 합니다."},turns:[{prompt:{en:"Good evening! Welcome. Do you have a reservation?",ko:"안녕하세요! 환영합니다. 예약하셨나요?"},template:"Yes, I have a reservation under {0} for {1}.",blanks:[[{en:"the name Kim",ko:"Kim이라는 이름",note:"이름을 구체적으로 댐"},{en:"my last name",ko:"제 성",note:"성으로 두루뭉술하게 안내"}],[{en:"three nights",ko:"3박",note:"사흘 숙박"},{en:"two nights",ko:"2박",note:"이틀 숙박"},{en:"the weekend",ko:"주말",note:"주말 동안으로 가볍게 표현"}]],example:{en:"Yes, I have a reservation under the name Kim for three nights.",ko:"네, Kim이라는 이름으로 3박 예약을 했습니다."}},{prompt:{en:"I found it. Would you prefer a room with a city view or a garden view?",ko:"찾았습니다. 시티 뷰 객실과 가든 뷰 객실 중 어느 쪽이 좋으세요?"},template:"I'd prefer a {0} room if possible, because I {1}.",blanks:[[{en:"city view",ko:"시티 뷰",note:"도심 전망을 선택"},{en:"garden view",ko:"가든 뷰",note:"정원 전망을 선택"},{en:"quiet",ko:"조용한",note:"전망보다 정숙함을 우선"}],[{en:"love the night lights",ko:"야경을 좋아한다",note:"취향을 이유로 댐"},{en:"sleep better with less noise",ko:"소음이 적을 때 더 잘 잔다",note:"실용적 이유를 댐"}]],example:{en:"I'd prefer a city view room if possible, because I love the night lights.",ko:"가능하다면 시티 뷰 객실이 좋겠습니다. 야경을 좋아하거든요."}},{prompt:{en:"Of course. What time would you like breakfast tomorrow?",ko:"물론이죠. 내일 아침 식사는 몇 시에 하시겠어요?"},template:"Around {0} would be perfect. Could you also tell me where {1} is?",blanks:[[{en:"eight o'clock",ko:"8시",note:"이른 아침 시간"},{en:"nine in the morning",ko:"아침 9시",note:"조금 늦은 아침 시간"}],[{en:"the gym",ko:"헬스장",note:"운동 시설 위치를 물음"},{en:"the breakfast room",ko:"조식 식당",note:"식사 장소 위치를 물음"},{en:"the nearest subway",ko:"가장 가까운 지하철역",note:"교통편 위치를 물음"}]],example:{en:"Around eight o'clock would be perfect. Could you also tell me where the gym is?",ko:"8시쯤이면 딱 좋겠습니다. 헬스장이 어디인지도 알려 주시겠어요?"}},{prompt:{en:"It's on the second floor. Here's your key card. Enjoy your stay!",ko:"2층에 있습니다. 여기 키 카드 드릴게요. 즐거운 시간 보내세요!"},template:"Thank you so much. By the way, is it okay to {0} if I need {1}?",blanks:[[{en:"call the front desk",ko:"프런트에 전화하다",note:"전화로 요청하는 방법"},{en:"come back down",ko:"다시 내려오다",note:"직접 내려와 묻는 방법"}],[{en:"extra towels",ko:"추가 수건",note:"비품 요청"},{en:"a late checkout",ko:"레이트 체크아웃",note:"퇴실 시간 연장 요청"},{en:"any help",ko:"도움",note:"포괄적인 도움 요청"}]],example:{en:"Thank you so much. By the way, is it okay to call the front desk if I need extra towels?",ko:"정말 감사합니다. 그런데 추가 수건이 필요하면 프런트에 전화해도 괜찮을까요?"}}]},{id:"scn-b1-work-meeting-001",level:"B1",situation:"work-meeting",title:{en:"Sharing an idea in a meeting",ko:"회의에서 의견 내기"},context:{en:"Your team is discussing how to improve a project in a meeting.",ko:"팀이 회의에서 프로젝트 개선 방안을 논의하고 있습니다."},turns:[{prompt:{en:"So, what does everyone think about the current schedule?",ko:"자, 현재 일정에 대해 다들 어떻게 생각하세요?"},template:"Honestly, I think the schedule is a bit {0}, so we might need to {1}.",blanks:[[{en:"tight",ko:"빠듯한",note:"여유가 적다는 완곡한 지적"},{en:"unrealistic",ko:"비현실적인",note:"아예 무리라는 강한 지적"},{en:"too relaxed",ko:"너무 느슨한",note:"오히려 늘어졌다는 반대 지적"}],[{en:"push the deadline",ko:"마감을 미루다",note:"기한 연장을 제안"},{en:"add more people",ko:"인원을 늘리다",note:"인력 보강을 제안"}]],example:{en:"Honestly, I think the schedule is a bit tight, so we might need to push the deadline.",ko:"솔직히 일정이 좀 빠듯한 것 같아서, 마감을 미뤄야 할 수도 있겠습니다."}},{prompt:{en:"That's a fair point. Do you have a suggestion?",ko:"일리 있는 말이네요. 제안할 것이 있나요?"},template:"Yes. I suggest we {0} this week, and then {1} next week.",blanks:[[{en:"focus on the design",ko:"디자인에 집중하다",note:"디자인 작업을 우선"},{en:"finish the research",ko:"조사를 마무리하다",note:"조사 작업을 우선"}],[{en:"start testing",ko:"테스트를 시작하다",note:"검증 단계로 넘어감"},{en:"review the results",ko:"결과를 검토하다",note:"결과를 되짚어 봄"},{en:"ask for feedback",ko:"피드백을 받다",note:"의견 수렴 단계로 넘어감"}]],example:{en:"Yes. I suggest we focus on the design this week, and then start testing next week.",ko:"네. 이번 주에는 디자인에 집중하고, 다음 주에 테스트를 시작하면 좋겠습니다."}},{prompt:{en:"I'm not sure we have the budget for that. What do you think?",ko:"거기에 쓸 예산이 있는지 잘 모르겠어요. 어떻게 생각하세요?"},template:"I understand your concern, but I believe it's worth it because it would {0} and {1}.",blanks:[[{en:"save time later",ko:"나중에 시간을 절약하다",note:"장기 효율을 근거로 듦"},{en:"reduce mistakes",ko:"실수를 줄이다",note:"오류 방지를 근거로 듦"}],[{en:"improve the quality",ko:"품질을 높이다",note:"결과물 완성도를 강조"},{en:"keep the client happy",ko:"고객을 만족시키다",note:"고객 만족을 강조"}]],example:{en:"I understand your concern, but I believe it's worth it because it would save time later and improve the quality.",ko:"걱정하시는 점은 이해하지만, 나중에 시간을 절약하고 품질도 높일 수 있어 그만한 가치가 있다고 생각합니다."}},{prompt:{en:"Okay, let's try it. Can you send a summary after the meeting?",ko:"좋아요, 그렇게 해 봅시다. 회의 후에 요약 좀 보내 줄 수 있어요?"},template:"Of course. I'll send the summary by {0}, and I'll also {1} so everyone is on the same page.",blanks:[[{en:"end of the day",ko:"오늘 퇴근 전",note:"오늘 안에 처리하겠다는 신속함"},{en:"tomorrow morning",ko:"내일 아침",note:"다음 날로 여유를 두는 톤"}],[{en:"share the timeline",ko:"일정표를 공유하다",note:"전체 일정을 공유"},{en:"list the next steps",ko:"다음 단계를 정리하다",note:"후속 할 일을 정리"}]],example:{en:"Of course. I'll send the summary by end of the day, and I'll also share the timeline so everyone is on the same page.",ko:"물론입니다. 오늘 퇴근 전까지 요약을 보내고, 모두가 같은 내용을 공유하도록 일정표도 함께 공유하겠습니다."}}]},{id:"scn-b1-making-plans-001",level:"B1",situation:"making-plans",title:{en:"Making weekend plans",ko:"주말 약속 정하기"},context:{en:"You and a friend are deciding what to do this weekend.",ko:"친구와 이번 주말에 무엇을 할지 정하고 있습니다."},turns:[{prompt:{en:"Hey, are you free this weekend? I was thinking we could do something.",ko:"야, 이번 주말에 시간 돼? 우리 뭐라도 같이 할까 싶어서."},template:"I'm free on {0}. I'd really like to {1} if you're up for it.",blanks:[[{en:"Saturday afternoon",ko:"토요일 오후",note:"구체적 시간대를 콕 집음"},{en:"Sunday",ko:"일요일",note:"요일만 가볍게 제시"}],[{en:"go hiking",ko:"등산을 가다",note:"활동적인 제안"},{en:"check out a new cafe",ko:"새로운 카페에 가 보다",note:"가볍게 탐방하는 제안"},{en:"watch a movie",ko:"영화를 보다",note:"편안하게 즐기는 제안"}]],example:{en:"I'm free on Saturday afternoon. I'd really like to go hiking if you're up for it.",ko:"토요일 오후에 시간 돼. 괜찮으면 등산 가고 싶어."}},{prompt:{en:"Hmm, hiking sounds tiring. What about something more relaxing?",ko:"음, 등산은 좀 피곤할 것 같은데. 좀 더 편한 거 어때?"},template:"That's fair. We could {0} instead, since the weather is supposed to be {1}.",blanks:[[{en:"visit a museum",ko:"박물관에 가다",note:"실내에서 즐기는 대안"},{en:"have a picnic",ko:"피크닉을 하다",note:"야외에서 즐기는 대안"}],[{en:"really nice",ko:"정말 좋은",note:"맑은 날씨를 전제"},{en:"a bit rainy",ko:"약간 비 오는",note:"궂은 날씨를 전제"},{en:"warm",ko:"따뜻한",note:"포근한 날씨를 전제"}]],example:{en:"That's fair. We could have a picnic instead, since the weather is supposed to be really nice.",ko:"그것도 맞네. 날씨가 정말 좋을 거라니까 대신 피크닉을 해도 좋겠다."}},{prompt:{en:"A picnic sounds perfect! Where should we meet?",ko:"피크닉 좋다! 어디서 만날까?"},template:"Let's meet at {0} around {1}. That way we'll have plenty of time.",blanks:[[{en:"the park entrance",ko:"공원 입구",note:"목적지 근처에서 만남"},{en:"the subway station",ko:"지하철역",note:"교통 거점에서 만남"}],[{en:"eleven",ko:"11시",note:"오전 늦게"},{en:"noon",ko:"정오",note:"정확히 점심 무렵"}]],example:{en:"Let's meet at the park entrance around eleven. That way we'll have plenty of time.",ko:"11시쯤 공원 입구에서 만나자. 그러면 시간이 넉넉할 거야."}},{prompt:{en:"Sounds good! Should I bring anything?",ko:"좋아! 내가 뭐 가져갈까?"},template:"If you could bring {0}, that would be great. I'll take care of {1}.",blanks:[[{en:"some drinks",ko:"음료",note:"마실 거리를 부탁"},{en:"a blanket",ko:"돗자리",note:"깔개를 부탁"},{en:"some snacks",ko:"간식",note:"주전부리를 부탁"}],[{en:"the sandwiches",ko:"샌드위치",note:"메인 음식을 맡음"},{en:"the rest",ko:"나머지",note:"남은 것 전부를 맡음"}]],example:{en:"If you could bring some drinks, that would be great. I'll take care of the sandwiches.",ko:"네가 음료를 가져와 주면 정말 좋겠어. 샌드위치는 내가 준비할게."}}]},{id:"scn-b1-customer-service-001",level:"B1",situation:"customer-service",title:{en:"Returning a faulty product",ko:"불량 제품 반품하기"},context:{en:"You go to a store to return a product that isn't working.",ko:"작동하지 않는 제품을 반품하러 매장에 갑니다."},turns:[{prompt:{en:"Hi, how can I help you today?",ko:"안녕하세요, 무엇을 도와드릴까요?"},template:"Hi. I bought {0} here last week, but unfortunately it {1}.",blanks:[[{en:"this speaker",ko:"이 스피커",note:"구매한 품목을 지칭"},{en:"this kettle",ko:"이 주전자",note:"구매한 품목을 지칭"},{en:"this charger",ko:"이 충전기",note:"구매한 품목을 지칭"}],[{en:"stopped working",ko:"작동을 멈췄다",note:"쓰다가 멈춘 경우"},{en:"won't turn on",ko:"켜지지 않는다",note:"아예 켜지지 않는 경우"}]],example:{en:"Hi. I bought this speaker here last week, but unfortunately it stopped working.",ko:"안녕하세요. 지난주에 여기서 이 스피커를 샀는데, 안타깝게도 작동을 멈췄어요."}},{prompt:{en:"I'm sorry to hear that. Do you have the receipt with you?",ko:"그러셨군요, 죄송합니다. 영수증 가지고 계세요?"},template:"Yes, I have it right here. I'd like to {0} if that's possible, or at least {1}.",blanks:[[{en:"get a refund",ko:"환불받다",note:"돈을 돌려받길 원함"},{en:"exchange it",ko:"교환하다",note:"같은 물건으로 바꾸길 원함"}],[{en:"have it repaired",ko:"수리받다",note:"고쳐서 쓰는 차선책"},{en:"get a replacement",ko:"교체품을 받다",note:"새 제품으로 받는 차선책"}]],example:{en:"Yes, I have it right here. I'd like to get a refund if that's possible, or at least have it repaired.",ko:"네, 여기 있습니다. 가능하다면 환불받고 싶고, 아니면 적어도 수리라도 받고 싶습니다."}},{prompt:{en:"Our policy allows a refund within 14 days. Could you tell me what happened?",ko:"저희 정책상 14일 이내에는 환불이 가능합니다. 무슨 일이 있었는지 말씀해 주시겠어요?"},template:"Sure. It worked fine at first, but after {0} it suddenly {1} for no reason.",blanks:[[{en:"a couple of days",ko:"며칠",note:"며칠 쓴 뒤 발생"},{en:"the first use",ko:"첫 사용",note:"처음 쓰자마자 발생"}],[{en:"stopped charging",ko:"충전이 안 됐다",note:"충전 문제로 콕 집음"},{en:"made a strange noise",ko:"이상한 소리가 났다",note:"소음 증상을 호소"},{en:"shut down",ko:"꺼졌다",note:"갑자기 꺼지는 증상"}]],example:{en:"Sure. It worked fine at first, but after a couple of days it suddenly stopped charging for no reason.",ko:"네. 처음엔 잘 작동했는데, 며칠 뒤에 갑자기 이유 없이 충전이 안 됐어요."}},{prompt:{en:"Understood. I'll process a full refund for you right now.",ko:"알겠습니다. 지금 바로 전액 환불 처리해 드리겠습니다."},template:"Thank you, I really appreciate it. How long will it take for {0} to {1}?",blanks:[[{en:"the refund",ko:"환불금",note:"환불 건을 격식 있게 지칭"},{en:"the money",ko:"그 금액",note:"돈을 편하게 지칭"}],[{en:"appear on my card",ko:"제 카드에 반영되다",note:"카드 환급에 초점"},{en:"be returned",ko:"돌아오다",note:"돌려받는 과정을 두루 표현"}]],example:{en:"Thank you, I really appreciate it. How long will it take for the refund to appear on my card?",ko:"감사합니다, 정말 고맙습니다. 환불금이 제 카드에 반영되기까지 얼마나 걸릴까요?"}}]},{id:"scn-b2-business-meeting-001",level:"B2",situation:"business-meeting",title:{en:"Steering a project meeting",ko:"프로젝트 회의 이끌기"},context:{en:"Your team is reviewing the quarterly roadmap. You raise an agenda item, push back on a proposal, suggest an alternative, and help the group reach agreement.",ko:"팀이 분기 로드맵을 검토합니다. 안건을 꺼내고, 제안에 이견을 표하고, 대안을 제시한 뒤 합의를 이끌어냅니다."},turns:[{prompt:{en:"Thanks everyone for joining. Shall we start with the launch timeline?",ko:"다들 참석해 주셔서 감사합니다. 출시 일정부터 시작할까요?"},template:"Before we do, I'd like to {0} the {1}, as it may {2} everything else.",blanks:[[{en:"revisit",ko:"다시 짚다",note:"이미 논의된 걸 재검토하는 어감"},{en:"raise",ko:"꺼내다",note:"새 안건을 처음 제기하는 표현"},{en:"flag",ko:"짚어두다",note:"주의 환기용으로 가볍게 짚음"}],[{en:"budget",ko:"예산",note:"비용·자금 문제에 초점"},{en:"scope",ko:"범위",note:"일의 범위·규모를 가리킴"},{en:"staffing question",ko:"인력 문제",note:"인력 배치 사안을 콕 집음"}],[{en:"affect",ko:"영향을 주다",note:"가장 무난한 일반적 표현"},{en:"shape",ko:"좌우하다",note:"방향을 형성한다는 어감"},{en:"constrain",ko:"제약하다",note:"제한을 건다는 강한 어감"}]],example:{en:"Before we do, I'd like to revisit the budget, as it may affect everything else.",ko:"그 전에 예산을 다시 짚고 싶은데요, 나머지 전부에 영향을 줄 수 있어서요."}},{prompt:{en:"Fair point. My proposal is to cut the QA phase to save two weeks.",ko:"일리 있네요. 제 제안은 QA 단계를 줄여서 2주를 아끼자는 겁니다."},template:"I see the appeal, but I'm {0} that {1} could {2} the product.",blanks:[[{en:"concerned",ko:"우려되는",note:"격식 있게 우려를 표하는 어감"},{en:"worried",ko:"걱정되는",note:"감정이 더 직접 드러나는 구어체"},{en:"uneasy",ko:"꺼림칙한",note:"막연히 마음이 편치 않은 완곡한 어감"}],[{en:"rushing it",ko:"서두르는 것",note:"성급함 자체를 문제 삼음"},{en:"cutting corners",ko:"대충 넘기는 것",note:"절차를 생략한다는 관용 표현"},{en:"skipping testing",ko:"테스트를 건너뛰는 것",note:"구체적으로 QA 생략을 지목"}],[{en:"undermine",ko:"약화시키다",note:"서서히 기반을 무너뜨리는 어감"},{en:"compromise",ko:"위태롭게 하다",note:"품질을 떨어뜨린다는 어감"},{en:"hurt",ko:"해치다",note:"가장 직설적이고 쉬운 표현"}]],example:{en:"I see the appeal, but I'm concerned that rushing it could undermine the product.",ko:"끌리는 건 알겠지만, 서두르면 제품을 약화시킬까 우려됩니다."}},{prompt:{en:"So what would you suggest instead?",ko:"그럼 대신 뭘 제안하시겠어요?"},template:"What if we {0} the timeline rather than {1}, and {2} the lower-priority features?",blanks:[[{en:"extend",ko:"연장하다",note:"기간을 늘린다는 단순 명확한 표현"},{en:"stagger",ko:"단계적으로 나누다",note:"시차를 두고 분산한다는 어감"},{en:"adjust",ko:"조정하다",note:"가장 포괄적이고 무난한 표현"}],[{en:"compressing it",ko:"압축하는 것",note:"기간을 무리하게 줄임"},{en:"cutting quality",ko:"품질을 깎는 것",note:"품질 희생을 직접 지목"},{en:"removing QA",ko:"QA를 없애는 것",note:"테스트 폐지를 콕 집음"}],[{en:"defer",ko:"미루다",note:"나중으로 보류한다는 격식체"},{en:"deprioritize",ko:"후순위로 두다",note:"우선순위를 낮춘다는 어감"},{en:"postpone",ko:"연기하다",note:"일정을 뒤로 미루는 일반 표현"}]],example:{en:"What if we extend the timeline rather than compressing it, and defer the lower-priority features?",ko:"압축하는 대신 일정을 연장하고, 우선순위가 낮은 기능은 미루면 어떨까요?"}},{prompt:{en:"That could work. Can everyone live with a one-week extension?",ko:"그럴 수 있겠네요. 다들 일주일 연장은 받아들일 수 있을까요?"},template:"That sounds {0} to me. I think it {1} quality with speed, so I'm {2}.",blanks:[[{en:"reasonable",ko:"합리적인",note:"이치에 맞는다는 일반적 동의"},{en:"sensible",ko:"타당한",note:"분별 있고 현명하다는 어감"},{en:"like a fair compromise",ko:"공정한 절충처럼",note:"양보가 공평하다는 점에 초점"}],[{en:"balances",ko:"균형을 맞추다",note:"두 가치를 저울질해 맞춤"},{en:"reconciles",ko:"조화시키다",note:"상충을 화해시킨다는 격식체"},{en:"squares",ko:"양립시키다",note:"상충을 무리 없이 맞물리게 한다는 어감"}],[{en:"on board",ko:"찬성합니다",note:"함께하겠다는 구어적 동의"},{en:"happy to support it",ko:"기꺼이 지지합니다",note:"흔쾌한 지지를 부드럽게 표현"},{en:"fully behind it",ko:"전적으로 동의합니다",note:"전폭적 지지를 강하게 강조"}]],example:{en:"That sounds reasonable to me. I think it balances quality with speed, so I'm on board.",ko:"제겐 합리적으로 들립니다. 품질과 속도의 균형을 맞춘다고 보고, 찬성합니다."}}]},{id:"scn-b2-negotiation-001",level:"B2",situation:"negotiation",title:{en:"Negotiating a contract",ko:"계약 조건 협상하기"},context:{en:"You are negotiating terms with a supplier. You open, counter their price, ask for a concession, and close toward a deal.",ko:"공급업체와 조건을 협상합니다. 협상을 열고, 가격에 반론하고, 양보를 요청한 뒤 합의로 마무리합니다."},turns:[{prompt:{en:"Our standard rate for this volume is $50 per unit.",ko:"이 물량 기준 저희 표준 단가는 개당 50달러입니다."},template:"I appreciate that, though {0} the quotes we've received, it's {1} what we {2}.",blanks:[[{en:"compared with",ko:"비교하면",note:"다른 견적과 나란히 견줌"},{en:"relative to",ko:"대비하면",note:"기준 대비라는 격식 있는 표현"},{en:"given",ko:"감안하면",note:"사정을 고려한다는 어감"}],[{en:"somewhat above",ko:"다소 웃도는",note:"약간 높다는 완곡한 표현"},{en:"a bit higher than",ko:"조금 높은",note:"가장 부드럽고 일상적인 표현"},{en:"well beyond",ko:"한참 넘는",note:"크게 초과한다는 강한 어감"}],[{en:"budgeted",ko:"예산으로 잡은",note:"확정 예산을 근거로 댐"},{en:"had in mind",ko:"염두에 둔",note:"막연히 생각해 둔 선"},{en:"were expecting",ko:"예상한",note:"기대한 수준에 초점"}]],example:{en:"I appreciate that, though compared with the quotes we've received, it's somewhat above what we budgeted.",ko:"감사합니다만, 저희가 받은 견적과 비교하면 예산으로 잡은 것보다 다소 웃돕니다."}},{prompt:{en:"I understand. What figure did you have in mind?",ko:"이해합니다. 어느 정도 금액을 생각하셨나요?"},template:"If you could {0} to $44, we'd be prepared to {1} a {2} commitment.",blanks:[[{en:"come down",ko:"낮추다",note:"가격을 내린다는 직접적 표현"},{en:"move",ko:"조정하다",note:"여지를 둔다는 완곡한 표현"},{en:"drop",ko:"내려주다",note:"곧장 그 값까지 내려달라는 어감"}],[{en:"sign off on",ko:"확정하다",note:"최종 승인한다는 비즈니스 표현"},{en:"commit to",ko:"약속하다",note:"확실히 약정하겠다는 강한 어감"},{en:"lock in",ko:"고정하다",note:"조건을 묶어 확정한다는 어감"}],[{en:"twelve-month",ko:"12개월",note:"기간을 구체 숫자로 명시"},{en:"larger annual",ko:"더 큰 연간",note:"연 단위 물량 확대를 강조"},{en:"long-term",ko:"장기",note:"기간을 두루뭉술 길게 표현"}]],example:{en:"If you could come down to $44, we'd be prepared to sign off on a twelve-month commitment.",ko:"44달러까지 낮춰주시면, 저희는 12개월 약정을 확정할 준비가 되어 있습니다."}},{prompt:{en:"$44 is tight for us. Could we meet in the middle at $47?",ko:"44달러는 저희에게 빠듯합니다. 중간인 47달러로 절충할 수 있을까요?"},template:"I could {0} $47, provided you {1} free shipping and {2} the payment terms to 60 days.",blanks:[[{en:"live with",ko:"받아들이다",note:"썩 내키진 않지만 감수한다는 어감"},{en:"agree to",ko:"동의하다",note:"가장 무난하고 명확한 표현"},{en:"accept",ko:"수용하다",note:"격식 있게 받아들인다는 어감"}],[{en:"throw in",ko:"끼워주다",note:"덤으로 얹어준다는 구어 표현"},{en:"include",ko:"포함하다",note:"조건에 넣는다는 중립적 표현"},{en:"cover",ko:"부담하다",note:"비용을 떠안아 준다는 어감"}],[{en:"extend",ko:"연장하다",note:"기간을 늘린다는 일반적 표현"},{en:"stretch",ko:"늘리다",note:"한계껏 늘려달라는 구어적 어감"},{en:"lengthen",ko:"길게 하다",note:"길이를 늘인다는 단순 표현"}]],example:{en:"I could live with $47, provided you throw in free shipping and extend the payment terms to 60 days.",ko:"무료 배송을 끼워주시고 결제 조건을 60일로 연장해 주신다면, 47달러는 받아들일 수 있습니다."}},{prompt:{en:"Free shipping I can do. 60-day terms are a stretch, but let's try it.",ko:"무료 배송은 가능합니다. 60일 조건은 부담스럽지만 한번 해보죠."},template:"Then I think we have a {0}. Why don't I {1} this in writing so we can {2} by Friday?",blanks:[[{en:"deal",ko:"거래",note:"성사됐다는 캐주얼한 표현"},{en:"agreement",ko:"합의",note:"공식적인 합의를 가리킴"},{en:"workable arrangement",ko:"실행 가능한 협의",note:"실현 가능성을 강조한 어감"}],[{en:"put",ko:"정리하다",note:"put in writing, 서면화 관용구"},{en:"draft",ko:"초안 작성하다",note:"초안을 쓴다는 격식체"},{en:"capture",ko:"담아내다",note:"문서로 또박또박 담아낸다는 어감"}],[{en:"finalize",ko:"마무리하다",note:"최종 확정한다는 격식체"},{en:"sign",ko:"서명하다",note:"서명 행위를 콕 집음"},{en:"wrap this up",ko:"이걸 매듭짓다",note:"마무리를 가볍게 표현한 구어"}]],example:{en:"Then I think we have a deal. Why don't I put this in writing so we can finalize by Friday?",ko:"그럼 거래가 성사된 것 같네요. 제가 서면으로 정리해서 금요일까지 마무리하면 어떨까요?"}}]},{id:"scn-b2-job-interview-advanced-001",level:"B2",situation:"job-interview-advanced",title:{en:"A senior role interview",ko:"고위 직책 면접"},context:{en:"You are interviewing for a leadership position. You describe your impact, handle a challenge question, frame a weakness, and ask a thoughtful question.",ko:"리더십 직책 면접을 봅니다. 성과를 설명하고, 곤란한 질문에 대응하고, 약점을 풀어내고, 사려 깊은 질문을 던집니다."},turns:[{prompt:{en:"Tell me about a time you made a real difference in your last role.",ko:"이전 직책에서 실질적인 변화를 만든 사례를 말씀해 주세요."},template:"In my previous role I {0} a process that ultimately {1} costs by 30% while {2} quality.",blanks:[[{en:"led",ko:"주도하다",note:"이끌었다는 리더십 강조"},{en:"overhauled",ko:"전면 개편하다",note:"통째로 뜯어고쳤다는 강한 어감"},{en:"streamlined",ko:"간소화하다",note:"군더더기를 덜어 효율화함"}],[{en:"reduced",ko:"절감하다",note:"격식 있는 성과 보고 표현"},{en:"cut",ko:"줄이다",note:"단호하고 직접적인 표현"},{en:"brought down",ko:"낮추다",note:"끌어내렸다는 구어적 어감"}],[{en:"preserving",ko:"유지하면서",note:"기존 수준을 지켜냈다는 어감"},{en:"maintaining",ko:"지키면서",note:"가장 무난한 일반 표현"},{en:"even improving",ko:"오히려 향상시키면서",note:"유지를 넘어 개선까지 강조"}]],example:{en:"In my previous role I led a process that ultimately reduced costs by 30% while preserving quality.",ko:"이전 직책에서 한 프로세스를 주도했고, 결국 품질을 유지하면서 비용을 30% 절감했습니다."}},{prompt:{en:"Impressive. But your resume shows a short stint at one company. Why?",ko:"인상적이네요. 그런데 이력서를 보면 한 회사 근무 기간이 짧던데, 이유가 있나요?"},template:"That's a fair question. {0}, the company {1}, so I chose to {2} rather than wait it out.",blanks:[[{en:"Candidly",ko:"솔직히 말하면",note:"꾸밈없이 털어놓는 어감"},{en:"To be transparent",ko:"투명하게 말씀드리면",note:"숨김없이 공개한다는 격식체"},{en:"In hindsight",ko:"돌이켜 보면",note:"지나고 나서 본다는 회고적 어감"}],[{en:"was restructured",ko:"구조조정되었다",note:"조직 개편이라는 중립적 사유"},{en:"pivoted away from my team",ko:"제 팀과 다른 방향으로 전환했다",note:"회사 방향 전환을 구체적으로 설명"},{en:"lost its funding",ko:"자금을 잃었다",note:"재정난이라는 외부 요인 강조"}],[{en:"seek a better fit",ko:"더 맞는 곳을 찾다",note:"궁합 맞는 곳을 찾는다는 어감"},{en:"move on proactively",ko:"선제적으로 옮기다",note:"먼저 능동적으로 행동했다는 강조"},{en:"pursue a clearer path",ko:"더 분명한 길을 택하다",note:"분명한 방향을 좇는다는 어감"}]],example:{en:"That's a fair question. Candidly, the company was restructured, so I chose to seek a better fit rather than wait it out.",ko:"타당한 질문입니다. 솔직히 회사가 구조조정되어서, 버티기보다 더 맞는 곳을 찾기로 했습니다."}},{prompt:{en:"And what would you say is your greatest weakness?",ko:"본인의 가장 큰 약점은 무엇이라고 보시나요?"},template:"I tend to {0}, so I've been {1} by {2} more deliberately to my team.",blanks:[[{en:"take on too much myself",ko:"혼자 너무 떠안다",note:"일을 떠안는 책임감형 약점"},{en:"over-prepare",ko:"과하게 준비하다",note:"지나친 완벽주의 성향"},{en:"dive into the detail",ko:"세부에 파고들다",note:"디테일에 집착하는 경향"}],[{en:"working on it",ko:"개선하고 있다",note:"가장 무난한 일반 표현"},{en:"addressing it",ko:"보완하고 있다",note:"문제로 인식해 다룬다는 어감"},{en:"actively correcting it",ko:"적극적으로 고치고 있다",note:"적극성을 강하게 강조"}],[{en:"delegating",ko:"위임하기",note:"업무를 넘기는 구체적 행동"},{en:"deferring",ko:"(판단을) 맡기기",note:"팀의 판단을 믿고 따른다는 어감"},{en:"handing ownership",ko:"주도권을 넘기기",note:"책임·권한까지 넘긴다는 강조"}]],example:{en:"I tend to take on too much myself, so I've been working on it by delegating more deliberately to my team.",ko:"혼자 너무 떠안는 편이라, 팀에 더 의식적으로 위임하면서 개선하고 있습니다."}},{prompt:{en:"Great. Do you have any questions for us?",ko:"좋습니다. 저희에게 궁금한 점이 있나요?"},template:"I do. {0} this role, how would you {1} success in the {2} months?",blanks:[[{en:"For someone stepping into",ko:"이 역할을 맡는 사람에게",note:"새로 부임하는 입장에서 묻는 어감"},{en:"Looking at",ko:"이 역할을 보면",note:"역할을 들여다본다는 중립적 표현"},{en:"Thinking about",ko:"이 역할을 두고",note:"역할을 곰곰이 생각하며 묻는 어감"}],[{en:"define",ko:"정의하다",note:"성공의 기준을 규정한다는 어감"},{en:"measure",ko:"측정하다",note:"수치·지표로 잰다는 초점"},{en:"evaluate",ko:"평가하다",note:"종합적으로 판단한다는 어감"}],[{en:"first six",ko:"첫 6개월",note:"기간을 6개월로 구체화"},{en:"early",ko:"초기 몇",note:"막연히 초반이라는 표현"},{en:"opening",ko:"처음 몇",note:"시작 시기를 가리키는 표현"}]],example:{en:"I do. For someone stepping into this role, how would you define success in the first six months?",ko:"있습니다. 이 역할을 맡는 사람에게, 첫 6개월의 성공을 어떻게 정의하시겠어요?"}}]},{id:"scn-b2-complaint-resolution-001",level:"B2",situation:"complaint-resolution",title:{en:"Resolving a service complaint",ko:"서비스 불만 해결하기"},context:{en:"A faulty product disrupted your business. You explain the issue firmly but politely, reject an inadequate offer, propose a fair remedy, and confirm next steps.",ko:"결함 제품이 업무에 차질을 줬습니다. 단호하지만 정중하게 문제를 설명하고, 미흡한 제안을 거절하고, 공정한 해결책을 제안한 뒤 다음 단계를 확인합니다."},turns:[{prompt:{en:"Hello, I understand there's an issue with your recent order?",ko:"안녕하세요, 최근 주문에 문제가 있다고 들었는데요?"},template:"Yes. The unit {0} on arrival, which {1} our operations for two days and {2} us several clients.",blanks:[[{en:"was faulty",ko:"결함이 있었다",note:"제품 자체 하자를 가리킴"},{en:"failed",ko:"작동하지 않았다",note:"기능이 멈췄다는 어감"},{en:"was damaged",ko:"파손돼 있었다",note:"배송 중 손상을 지목"}],[{en:"disrupted",ko:"차질을 빚게 했다",note:"흐름을 어지럽혔다는 일반 표현"},{en:"halted",ko:"멈추게 했다",note:"완전히 정지시켰다는 강한 어감"},{en:"set back",ko:"지연시켰다",note:"진행을 뒤로 미뤘다는 어감"}],[{en:"cost",ko:"잃게 했다",note:"대가를 치르게 했다는 격식체"},{en:"lost",ko:"잃게 만들었다",note:"직접 손실을 강조한 구어체"},{en:"nearly cost",ko:"거의 잃게 할 뻔했다",note:"아슬아슬했다는 완화된 어감"}]],example:{en:"Yes. The unit was faulty on arrival, which disrupted our operations for two days and cost us several clients.",ko:"네. 제품이 도착하자마자 결함이 있었고, 이틀간 업무에 차질을 빚어 고객 몇 분을 잃었습니다."}},{prompt:{en:"I'm sorry to hear that. We can offer you a 10% discount on your next order.",ko:"그 말씀을 들으니 유감입니다. 다음 주문 시 10% 할인을 제공해 드릴 수 있습니다."},template:"I'm afraid that {0} the situation. The fault {1} on your end, so a discount {2} the disruption.",blanks:[[{en:"doesn't reflect",ko:"반영하지 못하다",note:"상황과 동떨어졌다는 어감"},{en:"falls short of",ko:"미치지 못하다",note:"기대에 못 미친다는 격식체"},{en:"hardly addresses",ko:"거의 해결하지 못하다",note:"거의 무의미하다는 강한 어감"}],[{en:"lay",ko:"있었다",note:"책임 소재가 있었다는 격식체"},{en:"originated",ko:"비롯되었다",note:"거기서 발생했다는 어감"},{en:"clearly sat",ko:"분명히 있었다",note:"명백히 그쪽 책임이라 단언"}],[{en:"doesn't cover",ko:"보상하지 못하다",note:"손해를 메우지 못한다는 표현"},{en:"won't offset",ko:"상쇄하지 못하다",note:"맞상계되지 않는다는 어감"},{en:"fails to make up for",ko:"만회하지 못하다",note:"도저히 보전 안 된다는 강조"}]],example:{en:"I'm afraid that doesn't reflect the situation. The fault lay on your end, so a discount doesn't cover the disruption.",ko:"죄송하지만 그건 상황을 반영하지 못합니다. 결함은 귀사 측에 있었으니, 할인으로는 차질을 보상하지 못합니다."}},{prompt:{en:"I see your point. What would you consider fair?",ko:"말씀하신 바를 알겠습니다. 무엇이 공정하다고 보시나요?"},template:"I'd expect a {0} replacement plus {1} for the downtime. {2}, I'd like the shipping waived.",blanks:[[{en:"full",ko:"전액",note:"빠짐없이 전부라는 강조"},{en:"no-cost",ko:"무상",note:"비용 부담 없음을 강조"},{en:"like-for-like",ko:"동일 제품",note:"같은 사양으로 맞교환을 명시"}],[{en:"compensation",ko:"보상",note:"손해 전반에 대한 보상"},{en:"a partial refund",ko:"부분 환불",note:"일부 금액 환급으로 한정"},{en:"credit",ko:"크레딧",note:"다음 거래용 적립금 형태"}],[{en:"On top of that",ko:"그에 더해",note:"요구를 하나 더 얹는 어감"},{en:"Beyond that",ko:"그 외에도",note:"그 범위를 넘어선다는 어감"},{en:"Ideally",ko:"이왕이면",note:"가능하면 좋겠다는 완곡한 표현"}]],example:{en:"I'd expect a full replacement plus compensation for the downtime. On top of that, I'd like the shipping waived.",ko:"전액 교체와 더불어 가동 중단에 대한 보상을 기대합니다. 그에 더해 배송비도 면제받고 싶습니다."}},{prompt:{en:"That's reasonable. I'll arrange a replacement and a refund for the downtime today.",ko:"합리적입니다. 오늘 교체품과 가동 중단 환불을 처리하겠습니다."},template:"Thank you. Could you {0} that in an email, and {1} me a tracking number once it {2}?",blanks:[[{en:"confirm",ko:"확인해주다",note:"내용을 확정해 달라는 어감"},{en:"put",ko:"정리해주다",note:"put in email, 서면화 관용구"},{en:"document",ko:"기록해주다",note:"공식 문서로 남겨달라는 격식체"}],[{en:"send",ko:"보내다",note:"가장 무난하고 일상적인 표현"},{en:"share",ko:"공유하다",note:"정보를 함께 나눈다는 어감"},{en:"forward",ko:"전달하다",note:"받은 걸 넘겨준다는 어감"}],[{en:"ships",ko:"발송되다",note:"가장 일반적인 발송 표현"},{en:"goes out",ko:"출고되다",note:"물건이 나간다는 구어적 표현"},{en:"is dispatched",ko:"배송 처리되다",note:"격식 있는 물류 용어"}]],example:{en:"Thank you. Could you confirm that in an email, and send me a tracking number once it ships?",ko:"감사합니다. 그 내용을 이메일로 확인해 주시고, 발송되면 운송장 번호를 보내주시겠어요?"}}]},{id:"scn-b2-networking-001",level:"B2",situation:"networking",title:{en:"Networking at a conference",ko:"컨퍼런스에서 인맥 쌓기"},context:{en:"You meet a potential collaborator at an industry event. You break the ice, find common ground, propose staying in touch, and wrap up warmly.",ko:"업계 행사에서 협업 가능성이 있는 사람을 만납니다. 어색함을 풀고, 공통점을 찾고, 연락 유지를 제안한 뒤 따뜻하게 마무리합니다."},turns:[{prompt:{en:"Quite a turnout today, isn't it? Are you enjoying the talks?",ko:"오늘 참석자가 꽤 많죠? 강연은 즐기고 계세요?"},template:"I am, actually. The keynote on AI ethics really {0} with me — I {1} that field {2}.",blanks:[[{en:"resonated",ko:"와닿다",note:"마음 깊이 공명했다는 격식체"},{en:"struck a chord",ko:"공감을 일으키다",note:"심금을 울렸다는 관용 표현"},{en:"stuck",ko:"인상에 남다",note:"기억에 남았다는 캐주얼한 표현"}],[{en:"work in",ko:"종사하다",note:"그 분야에서 일한다는 일반 표현"},{en:"specialize in",ko:"전문으로 하다",note:"전문성을 강조하는 어감"},{en:"focus on",ko:"집중하다",note:"주력 분야라는 점에 초점"}],[{en:"myself",ko:"직접",note:"나 자신이 몸담고 있음을 강조"},{en:"professionally",ko:"직업적으로",note:"업으로 한다는 격식체"},{en:"day to day",ko:"일상적으로",note:"매일 다룬다는 실무 강조"}]],example:{en:"I am, actually. The keynote on AI ethics really resonated with me — I work in that field myself.",ko:"사실 그래요. AI 윤리 기조연설이 정말 와닿았어요. 제가 직접 그 분야에 종사하거든요."}},{prompt:{en:"Oh, what a coincidence — I lead a policy team in the same space.",ko:"어머, 우연이네요. 저도 같은 분야에서 정책 팀을 이끌고 있어요."},template:"What a small world. {0}, I've been meaning to {1} someone with a {2} perspective.",blanks:[[{en:"Honestly",ko:"솔직히",note:"속내를 털어놓는 친근한 어감"},{en:"As it happens",ko:"마침",note:"때마침 그렇다는 우연 강조"},{en:"Funnily enough",ko:"공교롭게도",note:"재미난 우연이라는 가벼운 어감"}],[{en:"connect with",ko:"연결되다",note:"인맥을 맺는다는 무난한 표현"},{en:"talk to",ko:"이야기 나누다",note:"가장 단순하고 일상적인 표현"},{en:"pick the brain of",ko:"조언을 구하다",note:"지식을 빌린다는 관용 표현"}],[{en:"policy",ko:"정책 관점의",note:"정책 분야 시각을 콕 집음"},{en:"regulatory",ko:"규제 관점의",note:"규제·법규 시각에 초점"},{en:"broader",ko:"더 넓은 관점의",note:"폭넓은 시야를 두루 가리킴"}]],example:{en:"What a small world. Honestly, I've been meaning to connect with someone with a policy perspective.",ko:"세상 참 좁네요. 솔직히 정책 관점을 가진 분과 연결되고 싶던 참이었어요."}},{prompt:{en:"I'd be glad to chat more. We could probably learn a lot from each other.",ko:"더 이야기 나누면 좋겠어요. 서로 배울 게 많을 것 같아요."},template:"I'd love that. {0} we grab a coffee sometime, or {1} over a call to {2} ideas?",blanks:[[{en:"Why don't",ko:"어떨까요",note:"가볍게 제안하는 친근한 어감"},{en:"Perhaps",ko:"혹시",note:"조심스럽게 떠보는 완곡함"},{en:"Shall",ko:"할까요",note:"함께하자고 권하는 정중한 표현"}],[{en:"connect",ko:"연결하다",note:"통화로 이어진다는 무난한 표현"},{en:"catch up",ko:"근황을 나누다",note:"안부·근황을 푼다는 친근한 어감"},{en:"follow up",ko:"후속 논의를 하다",note:"이어서 후속 대화를 한다는 어감"}],[{en:"exchange",ko:"주고받다",note:"서로 맞바꾼다는 일반 표현"},{en:"bounce around",ko:"자유롭게 나누다",note:"편하게 의견을 던져본다는 구어"},{en:"compare",ko:"견주어 보다",note:"서로 비교해 본다는 어감"}]],example:{en:"I'd love that. Why don't we grab a coffee sometime, or connect over a call to exchange ideas?",ko:"정말 좋아요. 언제 커피라도 하거나, 통화로 연결해서 아이디어를 주고받으면 어떨까요?"}},{prompt:{en:"Perfect. Here's my card — feel free to reach out anytime.",ko:"좋아요. 제 명함이에요. 언제든 편하게 연락 주세요."},template:"Wonderful — thank you. I'll {0} you next week, and {1} we can {2} a proper conversation.",blanks:[[{en:"message",ko:"메시지를 보내다",note:"문자·메신저로 연락한다는 어감"},{en:"email",ko:"이메일하다",note:"이메일 수단을 콕 집음"},{en:"reach out to",ko:"연락하다",note:"먼저 손 내밀어 닿는다는 어감"}],[{en:"hopefully",ko:"바라건대",note:"그러길 바란다는 조심스러운 기대"},{en:"I'm sure",ko:"분명",note:"확신한다는 단정적 어감"},{en:"no doubt",ko:"틀림없이",note:"의심의 여지 없다는 강한 확신"}],[{en:"set up",ko:"마련하다",note:"자리를 차린다는 구어적 표현"},{en:"arrange",ko:"잡다",note:"약속을 조율해 정한다는 어감"},{en:"schedule",ko:"일정을 정하다",note:"날짜·시간을 못 박는다는 어감"}]],example:{en:"Wonderful — thank you. I'll message you next week, and hopefully we can set up a proper conversation.",ko:"정말 좋네요, 감사합니다. 다음 주에 연락드릴게요. 바라건대 제대로 된 대화 자리를 마련할 수 있겠죠."}}]},{id:"scn-c1-negotiation-001",level:"C1",situation:"negotiation",title:{en:"Negotiating a partnership deal",ko:"제휴 계약 협상"},context:{en:"You are negotiating the terms of a supply partnership with a potential vendor.",ko:"잠재 공급업체와 공급 제휴 조건을 협상합니다."},turns:[{prompt:{en:"Thanks for coming in. Shall we get straight to the figures?",ko:"와 주셔서 감사합니다. 바로 수치부터 살펴볼까요?"},template:"By all means. Before we {0}, I'd like to {1} the {2} we're working toward.",blanks:[[{en:"dive into the numbers",ko:"수치를 파고들기",note:"숫자를 본격적으로 파고든다는 표현"},{en:"get into specifics",ko:"세부 사항으로 들어가기",note:"세부 논의로 넘어간다는 무난한 표현"},{en:"talk price",ko:"가격을 논의하기",note:"가격만 콕 집어 말하는 직설적 표현"}],[{en:"align on",ko:"합의해 두다",note:"방향을 미리 맞춰 둔다는 협업 어법"},{en:"clarify",ko:"명확히 하다",note:"모호한 부분을 분명히 한다는 뉘앙스"},{en:"lay out",ko:"제시하다",note:"목표를 펼쳐 보여 준다는 표현"}],[{en:"shared outcome",ko:"공동의 목표",note:"양측이 함께 바라는 결과를 강조"},{en:"broader goals",ko:"큰 그림의 목표",note:"더 넓은 차원의 목표를 강조"},{en:"end result",ko:"최종 결과",note:"최종 도달점에 초점을 둔 표현"}]],example:{en:"By all means. Before we dive into the numbers, I'd like to align on the shared outcome we're working toward.",ko:"물론이죠. 수치를 파고들기 전에, 우리가 지향하는 공동의 목표부터 합의해 두고 싶습니다."}},{prompt:{en:"Fair enough. Our standard rate is $50 per unit at this volume.",ko:"좋습니다. 이 물량 기준 단가는 개당 50달러가 표준입니다."},template:"I appreciate the {0}, but at that price the margins would be {1}. Could we {2} for a longer commitment?",blanks:[[{en:"transparency",ko:"투명함",note:"솔직히 공개해 준 점을 치켜세움"},{en:"candor",ko:"솔직함",note:"꾸밈없는 솔직함을 격식 있게 칭찬"},{en:"opening offer",ko:"첫 제안",note:"첫 제시안임을 중립적으로 지칭"}],[{en:"razor-thin",ko:"아주 빠듯한",note:"마진이 종잇장처럼 얇다는 비유"},{en:"hard to justify",ko:"정당화하기 어려운",note:"내부 설득이 어렵다는 우회 표현"},{en:"untenable",ko:"감당하기 힘든",note:"지속 불가능함을 격식 있게 단언"}],[{en:"revisit that",ko:"그 부분을 재고하다",note:"그 가격을 다시 보자는 부드러운 요청"},{en:"explore some flexibility",ko:"유연성을 검토하다",note:"여지를 함께 찾아보자는 완곡 제안"},{en:"find middle ground",ko:"절충점을 찾다",note:"절충안을 찾자는 직접적 제안"}]],example:{en:"I appreciate the transparency, but at that price the margins would be razor-thin. Could we revisit that for a longer commitment?",ko:"투명하게 말씀해 주셔서 감사합니다만, 그 가격이면 마진이 아주 빠듯합니다. 장기 약정을 전제로 그 부분을 재고할 수 있을까요?"}},{prompt:{en:"A longer term changes things. What did you have in mind?",ko:"장기 계약이라면 얘기가 달라지죠. 어떤 걸 염두에 두고 계신가요?"},template:"If we {0} to a three-year term, I'd hope you could {1} closer to $42. That would let us {2}.",blanks:[[{en:"commit",ko:"약정하다",note:"기간을 약속한다는 표준 표현"},{en:"lock ourselves in",ko:"확정하다",note:"스스로 묶인다는 다소 부담 섞인 뉘앙스"},{en:"sign on",ko:"계약하다",note:"계약에 서명·합류한다는 구어체"}],[{en:"come down",ko:"낮춰 주다",note:"가격을 내려 달라는 직접 요청"},{en:"meet us",ko:"맞춰 주다",note:"우리 쪽으로 맞춰 달라는 협상 어법"},{en:"land somewhere",ko:"어느 선에서 합의하다",note:"적정선에 안착하자는 완곡 표현"}],[{en:"scale together",ko:"함께 성장하다",note:"동반 성장의 비전을 강조"},{en:"grow the volume",ko:"물량을 키우다",note:"거래 물량 확대에 초점"},{en:"make the partnership worthwhile",ko:"제휴를 가치 있게 만들다",note:"제휴의 실익을 강조"}]],example:{en:"If we commit to a three-year term, I'd hope you could come down closer to $42. That would let us scale together.",ko:"3년 약정으로 가면, 42달러 선까지 낮춰 주시길 바랍니다. 그래야 우리가 함께 성장할 수 있습니다."}},{prompt:{en:"$42 is a stretch, but $45 with quarterly reviews could work.",ko:"42달러는 무리지만, 분기별 검토를 조건으로 45달러라면 가능합니다."},template:"That feels like a {0}. Let's {1} at $45 with quarterly reviews, and I'll {2} this week.",blanks:[[{en:"reasonable compromise",ko:"합리적인 절충",note:"합당한 타협임을 담백하게 평가"},{en:"deal we can both live with",ko:"서로 받아들일 만한 합의",note:"양측이 수용 가능함을 강조하는 관용구"},{en:"fair place to land",ko:"타당한 합의점",note:"공정한 착지점이라는 비유 표현"}],[{en:"shake on it",ko:"악수로 마무리하다",note:"악수로 합의를 매듭짓는 관용구"},{en:"put that in writing",ko:"서면으로 남기다",note:"구두 합의를 문서로 못 박자는 표현"},{en:"move forward",ko:"진행하다",note:"다음 단계로 나아가자는 무난한 표현"}],[{en:"draw up the contract",ko:"계약서를 작성하다",note:"직접 계약서를 작성하겠다는 표현"},{en:"loop in our legal team",ko:"법무팀을 합류시키다",note:"법무팀을 끌어들이겠다는 실무 표현"},{en:"send over the paperwork",ko:"서류를 보내다",note:"서류를 보내겠다는 가벼운 구어체"}]],example:{en:"That feels like a reasonable compromise. Let's shake on it at $45 with quarterly reviews, and I'll draw up the contract this week.",ko:"합리적인 절충 같습니다. 분기 검토 조건의 45달러로 악수하시죠. 계약서는 이번 주에 작성하겠습니다."}}]},{id:"scn-c1-presentation-qa-001",level:"C1",situation:"presentation-qa",title:{en:"Handling tough Q&A after a pitch",ko:"발표 후 까다로운 질의응답 대응"},context:{en:"You have just presented a product roadmap and are now fielding pointed questions from stakeholders.",ko:"제품 로드맵 발표를 마치고 이해관계자들의 날카로운 질문에 답하는 중입니다."},turns:[{prompt:{en:"Your timeline looks ambitious. What gives you confidence you'll hit it?",ko:"일정이 상당히 야심차 보이네요. 지킬 수 있다는 확신은 어디서 나오나요?"},template:"That's a {0} question. Our confidence {1} the fact that we've already {2} the riskiest phase.",blanks:[[{en:"fair",ko:"타당한",note:"질문이 정당하다고 가볍게 인정"},{en:"valid",ko:"정당한",note:"논리적 타당성을 인정하는 표현"},{en:"perfectly reasonable",ko:"충분히 합리적인",note:"지극히 합당함을 한층 강조"}],[{en:"rests on",ko:"~에 근거하다",note:"근거 위에 놓여 있다는 정적 비유"},{en:"comes down to",ko:"~로 귀결되다",note:"결국 한 가지로 압축된다는 표현"},{en:"stems from",ko:"~에서 비롯되다",note:"원천에서 비롯됨을 강조"}],[{en:"de-risked",ko:"위험을 줄여 두다",note:"리스크를 미리 제거했다는 전문 용어"},{en:"validated",ko:"검증해 두다",note:"타당성을 입증해 두었다는 표현"},{en:"prototyped",ko:"시제품화해 두다",note:"시제품으로 미리 만들어 봤다는 표현"}]],example:{en:"That's a fair question. Our confidence rests on the fact that we've already de-risked the riskiest phase.",ko:"타당한 질문입니다. 저희의 확신은 이미 가장 위험한 단계의 리스크를 줄여 두었다는 사실에 근거합니다."}},{prompt:{en:"But your competitor shipped something similar last month. Aren't you behind?",ko:"하지만 경쟁사가 지난달 비슷한 걸 출시했죠. 뒤처진 것 아닌가요?"},template:"I'd {0} that. What they shipped {1} the surface, whereas our approach {2} the underlying problem.",blanks:[[{en:"push back on",ko:"반론을 제기하다",note:"직접 반박하겠다는 비즈니스 관용구"},{en:"respectfully challenge",ko:"정중히 이의를 제기하다",note:"예의를 갖춰 반론하는 격식체"},{en:"take issue with",ko:"이의를 제기하다",note:"정중히 견해 차이를 드러내는 표현"}],[{en:"barely scratches",ko:"겉만 살짝 건드리다",note:"표면만 긁었다는 비유 관용구"},{en:"only touches",ko:"겉만 건드리다",note:"겉면만 손댔다는 담백한 지적"},{en:"skims",ko:"겉핥기로 다루다",note:"수박 겉핥기식임을 강조"}],[{en:"gets at",ko:"정곡을 찌르다",note:"핵심을 파고든다는 표현"},{en:"tackles",ko:"정면으로 다루다",note:"문제에 정면으로 맞선다는 표현"},{en:"goes after",ko:"파고들다",note:"적극적으로 공략한다는 뉘앙스"}]],example:{en:"I'd push back on that. What they shipped barely scratches the surface, whereas our approach gets at the underlying problem.",ko:"그 점엔 반론을 제기하고 싶습니다. 그들이 출시한 건 겉만 살짝 건드린 것이고, 저희 접근은 근본 문제를 정곡으로 찌릅니다."}},{prompt:{en:"What happens if engineering slips? Where's the contingency?",ko:"개발 일정이 밀리면 어떻게 되나요? 대비책은 뭐죠?"},template:"Good catch. We've {0} a buffer into Q3, so even if things {1}, the launch date {2}.",blanks:[[{en:"built",ko:"짜 넣다",note:"build into, 처음부터 여유를 짜 넣어 뒀다는 표현"},{en:"baked",ko:"포함시키다",note:"bake into, 녹여 넣었다는 구어 관용구"},{en:"factored",ko:"감안하다",note:"factor into, 계산에 미리 반영했다는 표현"}],[{en:"slip a little",ko:"조금 밀리다",note:"일정이 살짝 지연됨을 가볍게"},{en:"run long",ko:"예상보다 길어지다",note:"예상보다 오래 걸림을 표현"},{en:"hit a snag",ko:"차질이 생기다",note:"예기치 않은 걸림돌을 만난다는 관용구"}],[{en:"holds",ko:"유지되다",note:"흔들림 없이 지켜진다는 간결한 표현"},{en:"stays intact",ko:"그대로 유지되다",note:"온전히 그대로 보존됨을 강조"},{en:"won't budge",ko:"흔들리지 않다",note:"꿈쩍도 않는다는 단호한 강조"}]],example:{en:"Good catch. We've built a buffer into Q3, so even if things slip a little, the launch date holds.",ko:"좋은 지적입니다. 3분기에 여유를 내장해 두어서, 조금 밀리더라도 출시일은 유지됩니다."}},{prompt:{en:"Alright. I'm cautiously optimistic. Send me the detailed plan?",ko:"좋습니다. 조심스럽게 낙관해 보죠. 상세 계획을 보내 주시겠어요?"},template:"Absolutely. I'll {0} the full plan by Friday, and I'm happy to {1} offline if any of it {2}.",blanks:[[{en:"circulate",ko:"회람시키다",note:"여러 사람에게 돌려 본다는 격식체"},{en:"walk you through",ko:"차근차근 설명하다",note:"직접 단계별로 안내하겠다는 표현"},{en:"share",ko:"공유하다",note:"가장 무난하게 전달한다는 표현"}],[{en:"dig deeper",ko:"더 깊이 파고들다",note:"한층 깊이 파고들겠다는 표현"},{en:"hash it out",ko:"충분히 논의하다",note:"끝까지 따져 정리한다는 구어 관용구"},{en:"go point by point",ko:"항목별로 짚다",note:"하나씩 차례로 짚겠다는 표현"}],[{en:"needs clarifying",ko:"명확히 할 필요가 있다",note:"분명히 할 부분이 있다는 표현"},{en:"raises further questions",ko:"추가 의문을 낳다",note:"또 다른 의문이 생긴다는 표현"},{en:"warrants a closer look",ko:"더 들여다볼 가치가 있다",note:"정밀히 볼 가치가 있다는 격식체"}]],example:{en:"Absolutely. I'll circulate the full plan by Friday, and I'm happy to dig deeper offline if any of it needs clarifying.",ko:"물론입니다. 금요일까지 전체 계획을 회람하겠습니다. 명확히 할 부분이 있으면 따로 더 깊이 논의해 드리겠습니다."}}]},{id:"scn-c1-performance-review-001",level:"C1",situation:"performance-review",title:{en:"Advocating for a promotion in your review",ko:"성과 평가에서 승진을 어필하기"},context:{en:"In your annual performance review, you make the case for a promotion to your manager.",ko:"연간 성과 평가에서 매니저에게 승진을 설득합니다."},turns:[{prompt:{en:"You've had a strong year. How do you feel things have gone?",ko:"올해 성과가 좋았어요. 본인은 어떻게 평가하나요?"},template:"Thank you. I'd say I've {0} well beyond my role, particularly in {1} the launch that {2} the whole team.",blanks:[[{en:"stepped up",ko:"한 단계 더 나아가다",note:"책임을 맡고 분발했다는 관용구"},{en:"stretched",ko:"역량을 펼치다",note:"한계를 넘어 역량을 확장했다는 표현"},{en:"grown",ko:"성장하다",note:"꾸준히 성장했다는 담백한 표현"}],[{en:"spearheading",ko:"주도하다",note:"선봉에서 이끌었다는 강한 주도성"},{en:"driving",ko:"이끌다",note:"추진력 있게 끌고 갔다는 표현"},{en:"owning",ko:"전적으로 맡다",note:"전적인 책임을 졌다는 표현"}],[{en:"unblocked",ko:"걸림돌을 해소하다",note:"막힌 길을 뚫어 줬다는 표현"},{en:"galvanized",ko:"활력을 불어넣다",note:"팀에 활력을 불어넣었다는 격식체"},{en:"carried",ko:"이끌어 가다",note:"팀을 짊어지고 이끌었다는 뉘앙스"}]],example:{en:"Thank you. I'd say I've stepped up well beyond my role, particularly in spearheading the launch that unblocked the whole team.",ko:"감사합니다. 제 역할을 넘어서 한 단계 더 나아갔다고 봅니다. 특히 팀 전체의 걸림돌을 해소한 그 출시를 주도하면서요."}},{prompt:{en:"Agreed, that was impressive. So what are you hoping for next?",ko:"동의해요, 인상적이었죠. 그래서 다음으로 무엇을 바라나요?"},template:"I'd like to {0} a promotion to senior. I feel I've been {1} at that level for a while, and I'm ready to {2}.",blanks:[[{en:"make the case for",ko:"~을 주장하다",note:"근거를 들어 설득하겠다는 표현"},{en:"put myself forward for",ko:"~에 스스로를 내세우다",note:"스스로 후보로 나선다는 적극적 표현"},{en:"formally request",ko:"공식적으로 요청하다",note:"절차에 따라 정식 요청하는 격식체"}],[{en:"operating",ko:"활동하다",note:"그 수준에서 일해 왔다는 표현"},{en:"performing",ko:"성과를 내다",note:"이미 성과를 내 왔다는 강조"},{en:"delivering",ko:"결과를 내다",note:"결과물을 꾸준히 냈다는 표현"}],[{en:"take on more scope",ko:"더 넓은 범위를 맡다",note:"담당 범위 확대를 바란다는 표현"},{en:"lead from the front",ko:"앞장서서 이끌다",note:"솔선수범해 이끌겠다는 관용구"},{en:"own bigger bets",ko:"더 큰 도전을 책임지다",note:"더 큰 승부를 책임지겠다는 뉘앙스"}]],example:{en:"I'd like to make the case for a promotion to senior. I feel I've been operating at that level for a while, and I'm ready to take on more scope.",ko:"시니어로의 승진을 주장하고 싶습니다. 한동안 그 수준에서 일해 왔다고 느끼고, 더 넓은 범위를 맡을 준비가 됐습니다."}},{prompt:{en:"I hear you. Honestly, the scope question is where the panel may push back.",ko:"이해해요. 솔직히 범위 문제가 심사위원들이 이의를 제기할 지점일 거예요."},template:"That's fair. To {0} that, I've started {1} two juniors and {2} the architecture decisions — happy to document it.",blanks:[[{en:"get ahead of",ko:"선제적으로 대응하다",note:"문제를 앞질러 대비한다는 관용구"},{en:"address",ko:"해소하다",note:"정면으로 다뤄 해결한다는 표현"},{en:"preempt",ko:"미리 차단하다",note:"사전에 싹을 자른다는 강한 표현"}],[{en:"mentoring",ko:"멘토링하다",note:"장기적 성장을 이끄는 멘토 역할"},{en:"coaching",ko:"지도하다",note:"실무 역량을 코칭한다는 표현"},{en:"onboarding",ko:"적응을 돕다",note:"신규 인력의 안착을 돕는다는 표현"}],[{en:"owning",ko:"책임지다",note:"전적인 책임을 진다는 표현"},{en:"driving",ko:"주도하다",note:"추진력 있게 끌고 간다는 표현"},{en:"anchoring",ko:"중심을 잡다",note:"흔들리지 않게 중심을 잡는다는 비유"}]],example:{en:"That's fair. To get ahead of that, I've started mentoring two juniors and owning the architecture decisions — happy to document it.",ko:"타당한 지적입니다. 그 부분에 선제적으로 대응하고자, 주니어 두 명을 멘토링하고 아키텍처 결정을 책임지기 시작했습니다. 문서로 정리해 드리겠습니다."}},{prompt:{en:"That helps a lot. Put together a brag doc and I'll champion it upstairs.",ko:"큰 도움이 되네요. 성과 정리 문서를 만들어 주면 제가 위에 강하게 밀어 볼게요."},template:"I really {0} your support. I'll {1} the doc with metrics by next week, and I'm {2} the outcome with you.",blanks:[[{en:"appreciate",ko:"감사하게 여기다",note:"지원을 고맙게 여긴다는 표준 표현"},{en:"value",ko:"소중히 여기다",note:"지지를 값지게 평가한다는 뉘앙스"},{en:"am grateful for",ko:"고맙게 생각하다",note:"진심 어린 감사를 격식 있게"}],[{en:"pull together",ko:"정리해 모으다",note:"흩어진 자료를 그러모은다는 표현"},{en:"put together",ko:"작성하다",note:"문서를 만들어 낸다는 무난한 표현"},{en:"compile",ko:"취합하다",note:"체계적으로 취합한다는 격식체"}],[{en:"happy to share ownership of",ko:"기꺼이 함께 책임지다",note:"결과를 함께 책임지겠다는 협업 어법"},{en:"fully invested in",ko:"전적으로 몰입한",note:"결과에 온전히 헌신한다는 강조"},{en:"committed to delivering",ko:"함께 이뤄낼 각오가 된",note:"결과를 함께 이뤄내겠다는 동지애적 표현"}]],example:{en:"I really appreciate your support. I'll pull together the doc with metrics by next week, and I'm happy to share ownership of the outcome with you.",ko:"지원해 주셔서 정말 감사합니다. 다음 주까지 지표를 담은 문서를 정리하겠습니다. 결과는 기꺼이 함께 책임지겠습니다."}}]},{id:"scn-c1-conflict-mediation-001",level:"C1",situation:"conflict-mediation",title:{en:"Mediating a clash between teammates",ko:"팀원 간 갈등 중재하기"},context:{en:"Two of your colleagues are at odds over a missed handoff, and you step in to mediate.",ko:"두 동료가 업무 인수인계 누락을 두고 대립하고, 당신이 중재에 나섭니다."},turns:[{prompt:{en:"He dropped the ball and now I'm the one cleaning up the mess.",ko:"걔가 일을 그르쳤는데 뒷수습은 제가 하고 있잖아요."},template:"I can tell you're {0}, and that's completely understandable. Before we {1} blame, let's {2} what actually happened.",blanks:[[{en:"frustrated",ko:"답답한",note:"감정을 무난하게 짚어 주는 표현"},{en:"running on empty",ko:"지칠 대로 지친",note:"연료가 바닥났다는 소진 비유"},{en:"at your wit's end",ko:"어찌할 바를 모르는",note:"한계에 다다른 막막함을 강조"}],[{en:"assign",ko:"돌리다",note:"책임을 배정한다는 중립적 표현"},{en:"lay",ko:"탓을 돌리다",note:"lay blame, 잘잘못을 따져 탓을 지우는 부정적 뉘앙스"},{en:"get into",ko:"따지다",note:"시시비비를 파고든다는 구어체"}],[{en:"untangle",ko:"차근차근 풀다",note:"얽힌 실타래를 푼다는 비유"},{en:"piece together",ko:"조각을 맞추다",note:"흩어진 사실을 짜맞춘다는 표현"},{en:"walk back through",ko:"되짚어 보다",note:"처음부터 되돌아 짚어 본다는 표현"}]],example:{en:"I can tell you're frustrated, and that's completely understandable. Before we assign blame, let's untangle what actually happened.",ko:"답답하신 거 압니다. 충분히 이해돼요. 책임을 돌리기 전에, 실제로 무슨 일이 있었는지 차근차근 풀어 봅시다."}},{prompt:{en:"Honestly, I never got a clear handoff. The spec just appeared half-finished.",ko:"솔직히 명확한 인수인계를 받은 적이 없어요. 명세가 그냥 반쯤 만들다 만 채로 떠넘겨졌죠."},template:"So it sounds like there was a {0} on both sides. Rather than {1}, can we focus on what each of you {2} going forward?",blanks:[[{en:"breakdown in communication",ko:"의사소통 단절",note:"소통이 완전히 끊겼음을 진단"},{en:"genuine misunderstanding",ko:"진심 어린 오해",note:"악의 없는 오해였음을 부각해 감싸 줌"},{en:"gap in expectations",ko:"기대치의 간극",note:"서로의 기대 차이를 객관적으로 짚음"}],[{en:"rehashing the past",ko:"지난 일을 곱씹다",note:"지난 일을 되풀이해 들춘다는 표현"},{en:"dwelling on it",ko:"거기에 집착하다",note:"한 곳에 매여 곱씹는다는 뉘앙스"},{en:"relitigating who's right",ko:"누가 옳은지 다시 따지다",note:"잘잘못을 재차 가린다는 강한 표현"}],[{en:"needs from the other",ko:"상대에게 필요로 하는 것",note:"상대에게 바라는 바에 초점"},{en:"can commit to",ko:"약속할 수 있는 것",note:"각자 지킬 수 있는 약속에 초점"},{en:"will own",ko:"책임질 것",note:"각자 책임질 몫에 초점"}]],example:{en:"So it sounds like there was a breakdown in communication on both sides. Rather than rehashing the past, can we focus on what each of you needs from the other going forward?",ko:"그러니까 양쪽 다 의사소통에 단절이 있었던 것 같네요. 지난 일을 곱씹기보다, 앞으로 서로에게 무엇이 필요한지에 집중해 볼까요?"}},{prompt:{en:"I just want a heads-up before something lands on my plate. Is that unreasonable?",ko:"제 앞에 일이 떨어지기 전에 미리 귀띔만 해 달라는 거예요. 그게 무리한 요구인가요?"},template:"Not at all — that's a {0} ask. What if we {1} a quick sync at each handoff so nothing {2}?",blanks:[[{en:"perfectly reasonable",ko:"지극히 합리적인",note:"지극히 당연한 요청임을 인정"},{en:"completely fair",ko:"전적으로 타당한",note:"전적으로 공정하다고 지지"},{en:"low-cost",ko:"부담 없는",note:"비용·수고가 거의 없음을 강조"}],[{en:"build in",ko:"정착시키다",note:"절차로 아예 끼워 넣어 정착시킴"},{en:"agree to",ko:"합의하다",note:"서로 합의로 정한다는 표현"},{en:"put in place",ko:"마련하다",note:"장치·절차를 마련해 둔다는 표현"}],[{en:"falls through the cracks",ko:"사이로 빠져나가다",note:"틈새로 누락되는 일을 막자는 관용구"},{en:"catches anyone off guard",ko:"누구를 당황시키다",note:"허를 찔려 당황하는 일을 막자는 표현"},{en:"slips by unnoticed",ko:"눈에 띄지 않게 지나가다",note:"모르게 지나치는 일을 막자는 표현"}]],example:{en:"Not at all — that's a perfectly reasonable ask. What if we build in a quick sync at each handoff so nothing falls through the cracks?",ko:"전혀요. 지극히 합리적인 요청입니다. 인수인계마다 짧게 맞춰 보는 시간을 정착시켜서, 아무것도 사이로 빠져나가지 않게 하면 어떨까요?"}},{prompt:{en:"That works for me. I think we just needed someone to break the ice.",ko:"저는 좋아요. 그냥 누가 어색한 분위기를 풀어 줄 사람이 필요했던 것 같네요."},template:"I'm glad we could {0}. Let's {1} this conversation so we both {2}, and we'll revisit in two weeks.",blanks:[[{en:"clear the air",ko:"오해를 풀다",note:"묵은 앙금을 걷어 낸다는 관용구"},{en:"find common ground",ko:"공통분모를 찾다",note:"공통점을 찾아냈다는 표현"},{en:"talk it through",ko:"허심탄회하게 이야기하다",note:"터놓고 끝까지 이야기했다는 표현"}],[{en:"capture",ko:"기록하다",note:"내용을 놓치지 않고 담아 둔다는 표현"},{en:"write up",ko:"정리해 적다",note:"깔끔히 정리해 작성한다는 표현"},{en:"document",ko:"문서화하다",note:"공식 문서로 남긴다는 격식체"}],[{en:"stay on the same page",ko:"같은 이해를 유지하다",note:"인식을 일치시켜 둔다는 관용구"},{en:"hold ourselves accountable",ko:"스스로 책임을 지다",note:"스스로에게 책임을 부여한다는 표현"},{en:"know where we stand",ko:"서로의 입장을 명확히 하다",note:"각자 위치를 분명히 안다는 표현"}]],example:{en:"I'm glad we could clear the air. Let's capture this conversation so we both stay on the same page, and we'll revisit in two weeks.",ko:"오해를 풀 수 있어서 다행입니다. 이 대화를 글로 기록해서 둘 다 같은 이해를 유지하고, 2주 뒤에 다시 점검해 봅시다."}}]},{id:"scn-c1-client-pitch-001",level:"C1",situation:"client-pitch",title:{en:"Pitching a solution to a skeptical client",ko:"회의적인 고객에게 솔루션 제안하기"},context:{en:"You are pitching a consulting engagement to a client who has been burned by vendors before.",ko:"과거 업체에 데인 경험이 있는 고객에게 컨설팅 계약을 제안합니다."},turns:[{prompt:{en:"We've heard big promises before and got nothing. Why are you different?",ko:"거창한 약속은 전에도 들었지만 남은 게 없었어요. 당신들은 뭐가 다른가요?"},template:"I won't {0} you with promises. Instead, I'd rather {1} a small win first and let the results {2}.",blanks:[[{en:"bombard",ko:"퍼붓다",note:"약속을 쏟아붓지 않겠다는 비유"},{en:"dazzle",ko:"현혹하다",note:"과장된 약속으로 현혹하지 않겠다는 솔직함"},{en:"woo",ko:"구슬리다",note:"약속으로 환심을 사려 들지 않겠다는 뉘앙스"}],[{en:"prove out",ko:"실제로 입증하다",note:"실제 결과로 증명한다는 표현"},{en:"demonstrate",ko:"직접 보여 주다",note:"눈앞에 직접 시연한다는 표현"},{en:"earn",ko:"쟁취하다",note:"성과로 신뢰를 얻어 낸다는 뉘앙스"}],[{en:"speak for themselves",ko:"스스로 말하게 하다",note:"결과가 알아서 증명한다는 관용구"},{en:"do the talking",ko:"결과로 증명하다",note:"말 대신 결과가 대변한다는 표현"},{en:"build the trust",ko:"신뢰를 쌓다",note:"차근차근 신뢰를 구축한다는 표현"}]],example:{en:"I won't bombard you with promises. Instead, I'd rather prove out a small win first and let the results speak for themselves.",ko:"약속을 퍼붓진 않겠습니다. 대신 작은 성과부터 실제로 입증하고, 결과가 스스로 말하게 하고 싶습니다."}},{prompt:{en:"A pilot sounds nice, but pilots have a way of dragging on forever.",ko:"파일럿이야 듣기 좋지만, 파일럿이란 게 끝없이 늘어지기 마련이죠."},template:"I share that concern, which is why we'd {0} it to thirty days with a {1} success metric you {2} upfront.",blanks:[[{en:"box",ko:"한정하다",note:"범위를 가둬 제한한다는 비유"},{en:"time-box",ko:"기간을 못 박다",note:"기한을 못 박는다는 실무 용어"},{en:"limit",ko:"제한하다",note:"limit ... to, 상한을 두어 제한한다는 표현"}],[{en:"single",ko:"단일한",note:"딱 하나로 좁힌다는 강조"},{en:"clear-cut",ko:"명확한",note:"군더더기 없이 명료하다는 표현"},{en:"agreed-upon",ko:"합의된",note:"사전에 합의된 것임을 강조"}],[{en:"define",ko:"정의하다",note:"기준을 직접 규정한다는 표현"},{en:"sign off on",ko:"승인하다",note:"최종 결재·승인한다는 표현"},{en:"set",ko:"정하다",note:"가장 간결하게 정한다는 표현"}]],example:{en:"I share that concern, which is why we'd box it to thirty days with a single success metric you define upfront.",ko:"저도 그 우려에 공감합니다. 그래서 30일로 기간을 한정하고, 고객님이 처음에 직접 정하는 단일한 성공 지표를 둘 겁니다."}},{prompt:{en:"And if the pilot falls short of that metric? Then what?",ko:"그런데 파일럿이 그 지표에 못 미치면요? 그땐 어떻게 되죠?"},template:"Then you {0} nothing — we only {1} once we've {2}. The risk sits squarely with us.",blanks:[[{en:"owe",ko:"지불할 의무가 있다",note:"지불 의무가 발생한다는 표현"},{en:"pay",ko:"지불하다",note:"가장 단순하게 지불한다는 표현"},{en:"are on the hook for",ko:"부담하다",note:"on the hook for, 책임지고 떠안는다는 구어 관용구"}],[{en:"get paid",ko:"보수를 받다",note:"대가를 받는다는 일반적 표현"},{en:"invoice",ko:"청구하다",note:"청구서를 발행한다는 실무 용어"},{en:"collect",ko:"수금하다",note:"대금을 거둬들인다는 표현"}],[{en:"earned it",ko:"그만한 자격을 갖추다",note:"받을 자격을 입증했을 때를 강조"},{en:"moved the needle",ko:"실질적 변화를 만들다",note:"눈에 띄는 변화를 냈다는 관용구"},{en:"delivered",ko:"약속을 이행하다",note:"약속한 결과를 내놓았다는 표현"}]],example:{en:"Then you owe nothing — we only get paid once we've earned it. The risk sits squarely with us.",ko:"그러면 한 푼도 지불하지 않으셔도 됩니다. 저희는 그만한 자격을 갖춘 뒤에야 보수를 받습니다. 위험은 전적으로 저희가 집니다."}},{prompt:{en:"That's a refreshingly bold offer. You've got my attention.",ko:"놀라울 만큼 대담한 제안이네요. 관심이 생기는군요."},template:"I'm glad it {0}. Let me {1} a one-page scope today, and we can {2} as soon as you're comfortable.",blanks:[[{en:"resonates",ko:"공감을 얻다",note:"마음에 울림을 준다는 표현"},{en:"lands",ko:"와닿다",note:"메시지가 제대로 꽂혔다는 구어체"},{en:"strikes a chord",ko:"마음을 움직이다",note:"심금을 울린다는 관용구"}],[{en:"draft",ko:"초안을 작성하다",note:"초안을 직접 잡아 보겠다는 표현"},{en:"put together",ko:"마련하다",note:"문서를 만들어 내겠다는 무난한 표현"},{en:"send over",ko:"보내 드리다",note:"곧장 보내 주겠다는 가벼운 표현"}],[{en:"kick things off",ko:"착수하다",note:"본격적으로 시작한다는 관용구"},{en:"get the ball rolling",ko:"일을 시작하다",note:"일에 시동을 건다는 비유 관용구"},{en:"hit the ground running",ko:"곧바로 본격 가동하다",note:"시작하자마자 전력 질주한다는 관용구"}]],example:{en:"I'm glad it resonates. Let me draft a one-page scope today, and we can kick things off as soon as you're comfortable.",ko:"공감해 주셔서 다행입니다. 오늘 한 장짜리 범위 문서를 작성하겠습니다. 편하실 때 바로 착수할 수 있습니다."}}]},{id:"scn-c2-debate-001",level:"C2",situation:"debate",title:{en:"Opening a formal debate",ko:"공식 토론 개시"},context:{en:"You are the lead speaker in a televised debate on whether universal basic income should replace existing welfare programs. You open, field a rebuttal, counter it, and close.",ko:"기존 복지를 보편적 기본소득으로 대체할지 다루는 TV 토론의 대표 토론자입니다. 개시 발언, 반론 대응, 재반박, 마무리를 이어갑니다."},turns:[{prompt:{en:"Let's begin. In one minute, why should this house support replacing welfare with a universal basic income?",ko:"시작하겠습니다. 1분 안에, 이 토론장이 복지를 기본소득으로 대체하는 데 찬성해야 하는 이유는 무엇입니까?"},template:"I'd argue that the {0} case is {1}: a basic income {2} bureaucratic gatekeeping and {3} restores dignity to recipients.",blanks:[[{en:"moral",ko:"도덕적",note:"옳고 그름의 가치에 호소하는 프레임"},{en:"economic",ko:"경제적",note:"비용·효율 논리로 끌고 가는 프레임"},{en:"pragmatic",ko:"실용적",note:"이념 떠나 효과 위주로 보는 프레임"}],[{en:"compelling",ko:"설득력 있습니다",note:"거부하기 힘든 호소력을 강조"},{en:"all but unanswerable",ko:"거의 반박 불가입니다",note:"반론 여지 없음을 격식 있게 단언"},{en:"deceptively simple",ko:"겉보기보다 단순합니다",note:"단순해 보여도 깊다는 반전 어감"}],[{en:"dismantles",ko:"허물고",note:"구조를 체계적으로 해체한다는 강한 어감"},{en:"does away with",ko:"없애 버리고",note:"아예 치워 버린다는 구어 관용구"},{en:"sidesteps",ko:"피해 가고",note:"정면 대결 없이 우회한다는 뉘앙스"}],[{en:"in doing so",ko:"그렇게 함으로써",note:"앞 행위의 결과로 이어짐을 연결"},{en:"above all",ko:"무엇보다",note:"핵심임을 끌어올려 강조"},{en:"crucially",ko:"결정적으로",note:"결정적 한 방임을 부각하는 부사"}]],example:{en:"I'd argue that the moral case is compelling: a basic income dismantles bureaucratic gatekeeping and in doing so restores dignity to recipients.",ko:"저는 도덕적 논거가 설득력 있다고 주장하겠습니다. 기본소득은 관료적 문턱을 허물고, 그렇게 함으로써 수급자의 존엄을 회복시킵니다."}},{prompt:{en:"But surely handing everyone cash is fiscally reckless — where does the money come from?",ko:"하지만 모두에게 현금을 쥐여주는 건 재정적으로 무모하지 않습니까? 그 돈은 어디서 나옵니까?"},template:"{0} I'd push back on the premise: the figure looks {1} only if you {2} the administrative overhead we'd {3}.",blanks:[[{en:"With respect,",ko:"외람되지만,",note:"정중함을 앞세워 반박을 여는 격식체"},{en:"If I may,",ko:"한 말씀 드리면,",note:"발언권을 공손히 청하는 완곡 도입"},{en:"Let me be candid:",ko:"솔직히 말씀드리면:",note:"꾸밈없이 직격하겠다는 신호"}],[{en:"ruinous",ko:"파멸적으로",note:"재정을 거덜 낸다는 극단적 어감"},{en:"prohibitive",ko:"감당 불가로",note:"비용이 너무 커 막힌다는 격식 어휘"},{en:"alarming",ko:"우려스럽게",note:"경각심을 부르되 수위는 낮은 표현"}],[{en:"conveniently ignore",ko:"편의적으로 무시할",note:"유리하게 일부러 못 본 척한다는 비판"},{en:"leave out of the ledger",ko:"장부에서 빼놓을",note:"회계 비유로 누락을 꼬집는 표현"},{en:"fail to net off",ko:"상계하지 않을",note:"차감 계산을 빠뜨린다는 재무 전문어"}],[{en:"stand to eliminate",ko:"없앨 수 있는",note:"절감 이득을 얻게 된다는 어감"},{en:"no longer carry",ko:"더는 짊어지지 않을",note:"짐을 벗는다는 비유적 표현"},{en:"otherwise shoulder",ko:"어차피 짊어질",note:"안 그러면 떠안았을 비용임을 부각"}]],example:{en:"With respect, I'd push back on the premise: the figure looks ruinous only if you conveniently ignore the administrative overhead we'd stand to eliminate.",ko:"외람되지만 그 전제에 반박하겠습니다. 그 수치는, 우리가 없앨 수 있는 행정 비용을 편의적으로 무시할 때만 파멸적으로 보입니다."}},{prompt:{en:"Even so, won't unconditional payments erode the incentive to work?",ko:"그렇다 해도, 무조건 지급은 일할 동기를 갉아먹지 않겠습니까?"},template:"That objection {0} the evidence: pilot after pilot shows hours worked {1}, and the supposed 'idleness' effect {2} once you {3} for caregiving and study.",blanks:[[{en:"runs ahead of",ko:"앞서갑니다",note:"근거보다 성급히 앞질렀다는 비유"},{en:"outpaces",ko:"넘어섭니다",note:"증거 범위를 능가했다는 격식 어휘"},{en:"simply isn't borne out by",ko:"결코 뒷받침되지 않습니다",note:"데이터로 입증 안 됨을 단호히 단언"}],[{en:"barely moving",ko:"거의 변하지 않고",note:"사실상 그대로임을 구어로 강조"},{en:"holding steady",ko:"그대로 유지되며",note:"안정적으로 일정함을 표현"},{en:"dipping only marginally",ko:"미미하게만 줄며",note:"감소가 있으나 무시할 수준임을 인정"}],[{en:"all but vanishes",ko:"거의 사라집니다",note:"사실상 없어진다는 격식 강조"},{en:"evaporates",ko:"증발해 버립니다",note:"흔적 없이 사라진다는 생생한 비유"},{en:"fails to materialize",ko:"현실화되지 않습니다",note:"끝내 나타나지 않는다는 학술조"}],[{en:"control",ko:"통제하면",note:"변수를 통제한다는 통계 전문어"},{en:"account",ko:"고려하면",note:"셈에 넣어 감안한다는 일반형"},{en:"adjust",ko:"보정하면",note:"수치를 보정 처리한다는 어감"}]],example:{en:"That objection runs ahead of the evidence: pilot after pilot shows hours worked barely moving, and the supposed 'idleness' effect all but vanishes once you control for caregiving and study.",ko:"그 반론은 증거를 앞서갑니다. 여러 시범 사업에서 노동 시간은 거의 변하지 않았고, 이른바 '나태' 효과는 돌봄과 학업을 통제하면 거의 사라집니다."}},{prompt:{en:"Time for closing remarks. Leave us with your strongest line.",ko:"마무리 발언 시간입니다. 가장 강력한 한마디로 끝맺어 주십시오."},template:"{0}, the question isn't whether we can afford this — it's whether we can {1} afford the {2} we've all learned to {3}.",blanks:[[{en:"In the final analysis",ko:"결국",note:"모든 걸 따진 끝의 결론임을 알리는 격식구"},{en:"When all is said and done",ko:"모든 걸 따져 보면",note:"다 끝낸 마당에라는 구어 관용구"},{en:"Let me leave you with this",ko:"이 한마디로 끝맺겠습니다",note:"마지막 한 방을 예고하는 연설 클로징"}],[{en:"any longer",ko:"더 이상",note:"지속 불가함을 시간적으로 강조"},{en:"in good conscience",ko:"양심상",note:"도덕적 양심에 비추어라는 어감"},{en:"morally",ko:"도덕적으로",note:"윤리 차원을 곧장 못 박는 부사"}],[{en:"indignities",ko:"굴욕들을",note:"존엄을 해치는 수모를 포괄하는 격식어"},{en:"means-tested cruelty",ko:"자산 심사라는 잔인함을",note:"심사 제도 자체를 잔혹함으로 규정"},{en:"patchwork of stigma",ko:"낙인의 누더기를",note:"기운 듯 엉성한 제도라는 비유적 비판"}],[{en:"tolerate",ko:"용인하도록",note:"참고 받아들인다는 중립적 표현"},{en:"treat as normal",ko:"당연시하도록",note:"이상함을 정상으로 여긴다는 비판"},{en:"look past",ko:"외면하도록",note:"보고도 못 본 척한다는 어감"}]],example:{en:"In the final analysis, the question isn't whether we can afford this — it's whether we can any longer afford the indignities we've all learned to tolerate.",ko:"결국 문제는 우리가 이것을 감당할 수 있느냐가 아니라, 우리 모두가 용인하도록 배워 온 굴욕들을 더 이상 감당할 수 있느냐입니다."}}]},{id:"scn-c2-diplomacy-001",level:"C2",situation:"diplomacy",title:{en:"Defusing a diplomatic standoff",ko:"외교적 교착 풀기"},context:{en:"As a senior envoy, you meet your counterpart after a breakdown in trade talks. You de-escalate, probe their red lines, offer a face-saving path, and seal a tentative understanding.",ko:"고위 특사로서, 무역 협상 결렬 후 상대측 인사를 만납니다. 긴장을 낮추고, 그들의 마지노선을 탐색하고, 체면을 살리는 길을 제시하고, 잠정 합의를 매듭짓습니다."},turns:[{prompt:{en:"Frankly, after last week, I'm not sure there's anything left to discuss.",ko:"솔직히 지난주 일을 겪고 나니, 더 논의할 게 남아 있는지 모르겠습니다."},template:"{0} the frustration on your side, and I won't {1} it. But I'd suggest the breakdown owes more to {2} than to any {3} difference between us.",blanks:[[{en:"I appreciate",ko:"충분히 이해합니다",note:"상대 감정을 따뜻이 헤아리는 외교어"},{en:"I don't underestimate",ko:"과소평가하지 않습니다",note:"그 무게를 가볍게 안 본다는 어감"},{en:"Let me acknowledge",ko:"인정하겠습니다",note:"존재 자체를 공식 인정하는 격식체"}],[{en:"paper over",ko:"덮으려",note:"겉만 가려 봉합한다는 비유적 관용구"},{en:"make light of",ko:"가볍게 여기려",note:"대수롭잖게 취급한다는 어감"},{en:"talk past",ko:"외면하려",note:"딴소리로 비껴간다는 뉘앙스"}],[{en:"a failure of sequencing",ko:"순서의 어긋남에",note:"내용 아닌 진행 순서 탓으로 돌림"},{en:"crossed wires",ko:"오해와 엇갈림에",note:"신호가 꼬였다는 구어 관용구"},{en:"timing and optics",ko:"시점과 모양새에",note:"본질 아닌 외형·타이밍 문제로 봄"}],[{en:"irreconcilable",ko:"화해 불가한",note:"끝내 못 좁힌다는 가장 강한 어감"},{en:"fundamental",ko:"근본적인",note:"뿌리부터 다르다는 어감"},{en:"substantive",ko:"실질적인",note:"형식 아닌 알맹이의 차이를 지칭"}]],example:{en:"I appreciate the frustration on your side, and I won't paper over it. But I'd suggest the breakdown owes more to a failure of sequencing than to any irreconcilable difference between us.",ko:"귀측의 답답함을 충분히 이해하며, 그것을 덮으려 하지 않겠습니다. 다만 이번 결렬은 우리 사이의 화해 불가한 차이라기보다 순서의 어긋남 탓이 크다고 봅니다."}},{prompt:{en:"Perhaps. But my capital will not move on the tariff schedule. That line is fixed.",ko:"그럴지도요. 하지만 우리 본국은 관세 일정에서 물러서지 않습니다. 그 선은 고정입니다."},template:"Understood — and I won't {0} you to cross it. {1}, might there be {2} in the phasing, even if the {3} stays untouched?",blanks:[[{en:"press",ko:"압박하지",note:"은근히 밀어붙인다는 점잖은 표현"},{en:"ask",ko:"요청하지",note:"정중히 부탁한다는 가장 부드러운 어감"},{en:"force",ko:"강요하지",note:"억지로 넘게 만든다는 가장 강한 표현"}],[{en:"That said",ko:"그렇지만",note:"앞말 인정 후 전환하는 무난한 연결"},{en:"If I read you correctly",ko:"제가 제대로 이해했다면",note:"상대 의중을 짚어 본다는 탐색조"},{en:"Setting the headline aside",ko:"표면적 수치는 차치하고",note:"겉수치를 제쳐 두자는 협상 화법"}],[{en:"room to maneuver",ko:"운신의 여지가",note:"움직일 공간이라는 외교 정착어"},{en:"latitude",ko:"재량이",note:"허용된 자유 폭을 뜻하는 격식 어휘"},{en:"give",ko:"여지가",note:"조금 양보할 틈이라는 구어적 표현"}],[{en:"headline figure",ko:"표면 수치는",note:"겉으로 내세우는 대표 숫자"},{en:"topline",ko:"최상단 수치는",note:"맨 윗줄 총액을 뜻하는 비즈니스어"},{en:"ceiling",ko:"상한은",note:"넘을 수 없는 한도를 가리킴"}]],example:{en:"Understood — and I won't press you to cross it. That said, might there be room to maneuver in the phasing, even if the headline figure stays untouched?",ko:"이해했습니다. 그 선을 넘으라 압박하지 않겠습니다. 그렇지만 표면 수치는 손대지 않더라도, 단계적 적용에는 운신의 여지가 있지 않을까요?"}},{prompt:{en:"Phasing... that I could take back. But my minister needs to be seen winning something.",ko:"단계적 적용이라면... 가지고 돌아갈 수 있겠군요. 하지만 우리 장관이 무언가 얻어 낸 모습은 보여야 합니다."},template:"Then let's {0} him a win he can {1}: announce the phased relief as {2}, and we'll {3} the framing entirely to your side.",blanks:[[{en:"hand",ko:"안겨",note:"성과를 직접 쥐여 준다는 일상어"},{en:"secure",ko:"따내",note:"치밀하게 따내 안겨 준다는 어감"},{en:"craft",ko:"지어내",note:"공들여 만들어 안겨 준다는 표현"}],[{en:"take to the podium",ko:"연단에서 내세울",note:"공개 발표 자리에서 과시한다는 비유"},{en:"sell at home",ko:"본국에서 내세울",note:"자국민에게 홍보한다는 정치 화법"},{en:"claim credit for",ko:"공으로 내세울",note:"성과를 제 공으로 가져간다는 어감"}],[{en:"his initiative",ko:"그의 주도로",note:"그가 먼저 이끈 것처럼 명분을 줌"},{en:"a concession he secured",ko:"그가 얻어 낸 양보로",note:"그가 따낸 양보로 포장한다는 어감"},{en:"a breakthrough",ko:"돌파구로",note:"교착을 뚫은 성과로 격상시킴"}],[{en:"cede",ko:"양보하겠습니다",note:"권리·명분을 내준다는 격식 어휘"},{en:"concede",ko:"내어드리겠습니다",note:"마지못해 인정해 준다는 어감"},{en:"hand over",ko:"넘겨드리겠습니다",note:"통째로 건넨다는 일상적 표현"}]],example:{en:"Then let's hand him a win he can take to the podium: announce the phased relief as his initiative, and we'll cede the framing entirely to your side.",ko:"그렇다면 그가 연단에서 내세울 성과를 안겨 드리죠. 단계적 완화를 그의 주도로 발표하시고, 그 명분은 전적으로 귀측에 양보하겠습니다."}},{prompt:{en:"That... could work. Shall we put something on paper before we lose the momentum?",ko:"그건... 될 수도 있겠군요. 동력을 잃기 전에 문서로 남겨 볼까요?"},template:"Let's {0} it as a non-binding understanding tonight, {1} the technical annexes to the working level, and {2} our principals brief the press {3}.",blanks:[[{en:"capture",ko:"담아 두고",note:"요지를 글로 포착해 둔다는 어감"},{en:"record",ko:"기록해 두고",note:"차분히 글로 남겨 둔다는 표현"},{en:"formalize",ko:"공식화해 두고",note:"공식 문서로 못 박아 둔다는 단단한 어감"}],[{en:"hand off",ko:"넘기고",note:"다음 단계로 인계한다는 일상어"},{en:"delegate",ko:"위임하고",note:"권한을 공식 이양한다는 격식체"},{en:"kick",ko:"넘기고",note:"실무로 차 넘긴다는 가벼운 구어"}],[{en:"have",ko:"하도록 하시죠",note:"~하게 시킨다는 사역의 기본형"},{en:"let",ko:"하게 하시죠",note:"허용·방임의 부드러운 어감"},{en:"make",ko:"하도록 하시죠",note:"~하도록 시키는 사역의 격식체"}],[{en:"in lockstep",ko:"보조를 맞춰",note:"한 치 어긋남 없이 발맞춘다는 관용구"},{en:"from the same script",ko:"같은 원고로",note:"동일한 메시지로 통일한다는 비유"},{en:"in parallel",ko:"동시에",note:"나란히 병행한다는 중립적 표현"}]],example:{en:"Let's capture it as a non-binding understanding tonight, hand off the technical annexes to the working level, and have our principals brief the press in lockstep.",ko:"오늘 밤 구속력 없는 양해로 담아 두고, 기술적 부속서는 실무진에 넘기고, 양측 수뇌가 보조를 맞춰 언론에 설명하도록 하시죠."}}]},{id:"scn-c2-board-meeting-001",level:"C2",situation:"board-meeting",title:{en:"Defending strategy to the board",ko:"이사회에 전략 방어"},context:{en:"As CEO, you present a plan to pause buybacks and reinvest in R&D. A skeptical board challenges you on returns, dilution, and timing; you hold your ground and win the room.",ko:"CEO로서, 자사주 매입을 멈추고 R&D에 재투자하는 계획을 발표합니다. 회의적인 이사회가 수익률, 희석, 시점을 문제 삼지만, 당신은 입장을 지키며 좌중을 설득합니다."},turns:[{prompt:{en:"The room is yours. Make the case for halting buybacks at the very moment shareholders expect them.",ko:"발언권을 드리죠. 주주들이 자사주 매입을 기대하는 바로 그 시점에 그것을 멈추자는 근거를 대 보십시오."},template:"I'll be {0}: buybacks {1} the share price, but they {2} a single product, and we are {3} on innovation that compounds.",blanks:[[{en:"blunt",ko:"단도직입적으로 말하죠",note:"에두름 없이 직격하겠다는 선언"},{en:"direct",ko:"직설적으로 말하죠",note:"곧장 본론으로 간다는 무난한 표현"},{en:"unsparing",ko:"에누리 없이 말하죠",note:"봐주지 않고 가차 없이라는 어감"}],[{en:"flatter",ko:"돋보이게 하지만",note:"실속 없이 겉만 띄운다는 비판조"},{en:"prop up",ko:"떠받치지만",note:"인위적으로 받쳐 올린다는 어감"},{en:"juice",ko:"끌어올리지만",note:"단기 부양한다는 격의 없는 구어"}],[{en:"fund",ko:"키워 내지",note:"자금을 대 길러낸다는 어감"},{en:"build",ko:"만들어 내지",note:"실제로 지어 만든다는 기본형"},{en:"ship",ko:"출시하지",note:"제품을 시장에 내놓는다는 업계 구어"}],[{en:"running on fumes",ko:"거의 바닥난 상태입니다",note:"연료가 동난다는 위기감 관용구"},{en:"living off the past",ko:"과거의 유산으로 버티고 있습니다",note:"옛 성과로 연명한다는 비판적 비유"},{en:"falling behind",ko:"뒤처지고 있습니다",note:"경쟁에서 밀려나고 있다는 어감"}]],example:{en:"I'll be blunt: buybacks flatter the share price, but they fund a single product, and we are running on fumes on innovation that compounds.",ko:"단도직입적으로 말하죠. 자사주 매입은 주가를 돋보이게 하지만, 정작 어떤 제품도 키워 내지 못하고, 우리는 복리로 쌓이는 혁신에서 거의 바닥난 상태입니다."}},{prompt:{en:"And if the R&D bets don't pay off? We'll have torched cash and the stock with it.",ko:"R&D 베팅이 결실을 못 맺으면요? 현금을 태우고 주가까지 같이 날릴 텐데요."},template:"{0} the downside, but let's size it honestly: we're {1} eight percent of free cash flow, {2} across a portfolio, with {3} at six months.",blanks:[[{en:"I won't sugarcoat",ko:"포장하지 않겠습니다",note:"달콤하게 꾸미지 않겠다는 관용구"},{en:"I take",ko:"받아들입니다",note:"지적을 담담히 수용한다는 간결체"},{en:"Let's not minimize",ko:"축소하지 맙시다",note:"위험을 작게 보지 말자는 환기"}],[{en:"ring-fencing",ko:"따로 떼어 둔",note:"용도를 칸막이해 격리한다는 재무어"},{en:"committing",ko:"투입하는",note:"자원을 약정 투입한다는 격식체"},{en:"staking",ko:"거는",note:"판돈처럼 건다는 베팅 어감"}],[{en:"spread",ko:"분산해",note:"여러 곳에 흩어 둔다는 일상어"},{en:"diversified",ko:"다각화해",note:"포트폴리오 분산의 정착 용어"},{en:"hedged",ko:"헤지해",note:"위험을 상쇄 대비한다는 금융 전문어"}],[{en:"kill switches",ko:"중단 기준을",note:"즉시 끊는 비상 장치라는 비유"},{en:"off-ramps",ko:"철수 지점을",note:"빠져나갈 출구를 미리 둔다는 어감"},{en:"stage gates",ko:"단계별 관문을",note:"단계마다 통과 심사를 둔다는 관리 용어"}]],example:{en:"I won't sugarcoat the downside, but let's size it honestly: we're ring-fencing eight percent of free cash flow, spread across a portfolio, with kill switches at six months.",ko:"하방 위험을 포장하지 않겠습니다. 다만 정직하게 규모를 따져 보죠. 잉여현금흐름의 8퍼센트만 따로 떼어, 포트폴리오로 분산하고, 6개월 시점에 중단 기준을 둡니다."}},{prompt:{en:"Our largest holder will read this as the board blinking. How do we hold them?",ko:"최대 주주는 이걸 이사회가 흔들리는 신호로 읽을 겁니다. 어떻게 붙잡죠?"},template:"We get {0} of them first, {1} the narrative as discipline rather than retreat, and {2} a milestone dividend that {3} them they haven't been forgotten.",blanks:[[{en:"out ahead",ko:"선수를 쳐서",note:"한발 앞서 선제 대응한다는 관용구"},{en:"in front",ko:"먼저 만나서",note:"직접 대면해 챙긴다는 무난한 표현"},{en:"ahead",ko:"앞서서",note:"시점상 미리라는 간결한 어감"}],[{en:"frame",ko:"규정하고",note:"유리한 틀로 의미를 짜 준다는 전략어"},{en:"cast",ko:"내세우고",note:"특정 인상으로 비치게 한다는 어감"},{en:"position",ko:"자리매김하고",note:"전략적 위치로 포지셔닝한다는 표현"}],[{en:"dangle",ko:"내걸어",note:"당근처럼 매달아 유혹한다는 어감"},{en:"commit to",ko:"약속해",note:"확실히 못 박아 약정한다는 격식체"},{en:"float",ko:"제시해",note:"확정 아닌 운만 띄워 본다는 어감"}],[{en:"reassures",ko:"안심시키도록",note:"불안을 다독여 안심시킨다는 어감"},{en:"signals to",ko:"신호를 주도록",note:"메시지를 은근히 전한다는 표현"},{en:"reminds",ko:"상기시키도록",note:"잊지 않았음을 일깨운다는 어감"}]],example:{en:"We get out ahead of them first, frame the narrative as discipline rather than retreat, and dangle a milestone dividend that reassures them they haven't been forgotten.",ko:"그들에게 먼저 선수를 쳐서, 이번 결정을 후퇴가 아닌 규율로 규정하고, 그들이 잊히지 않았음을 안심시키는 성과 연동 배당을 내걸겠습니다."}},{prompt:{en:"Suppose we back you. What do you want from this board, concretely?",ko:"우리가 당신을 지지한다고 칩시다. 이 이사회에서 구체적으로 무엇을 원합니까?"},template:"{0}: a two-year runway with {1} reviews, the {2} to redeploy within the envelope, and your public backing so the market {3} a unified front.",blanks:[[{en:"Three things",ko:"세 가지입니다",note:"요구를 셋으로 깔끔히 묶는 화법"},{en:"In plain terms",ko:"분명히 말씀드리면",note:"에두름 없이 명료하게라는 어감"},{en:"Concretely",ko:"구체적으로는",note:"추상론 접고 실무로 좁히는 표현"}],[{en:"quarterly",ko:"분기별",note:"3개월마다라는 정기 점검 주기"},{en:"milestone-gated",ko:"성과 관문별",note:"성과 달성마다 검토한다는 관리 용어"},{en:"no-surprises",ko:"돌발 없는",note:"예상 밖 일이 없게 한다는 어감"}],[{en:"mandate",ko:"권한을",note:"공식 위임된 강한 결정권"},{en:"discretion",ko:"재량을",note:"스스로 판단할 자유 폭"},{en:"latitude",ko:"여지를",note:"허용된 융통의 폭이라는 어감"}],[{en:"sees",ko:"보도록",note:"눈으로 확인하게 한다는 기본형"},{en:"reads",ko:"읽도록",note:"신호로 해석하게 한다는 어감"},{en:"is met with",ko:"마주하도록",note:"그것과 맞닥뜨리게 한다는 격식체"}]],example:{en:"Three things: a two-year runway with quarterly reviews, the mandate to redeploy within the envelope, and your public backing so the market sees a unified front.",ko:"세 가지입니다. 분기별 검토가 붙은 2년의 활주로, 한도 안에서 재배치할 권한, 그리고 시장이 단일 대오를 보도록 하는 여러분의 공개적 지지입니다."}}]},{id:"scn-c2-academic-defense-001",level:"C2",situation:"academic-defense",title:{en:"Defending a doctoral thesis",ko:"박사 논문 심사 방어"},context:{en:"You defend your dissertation before a committee. An examiner challenges your methodology, your novelty, and the limits of your claims; you concede where fair and defend where firm.",ko:"심사위원회 앞에서 박사 학위 논문을 변호합니다. 한 심사위원이 방법론, 독창성, 주장의 한계를 파고들고, 당신은 타당한 곳은 인정하고 굳건한 곳은 방어합니다."},turns:[{prompt:{en:"Your sample is small and self-selected. Why should we trust any inference you draw from it?",ko:"표본이 작고 자기 선택적입니다. 거기서 끌어낸 추론을 우리가 왜 신뢰해야 합니까?"},template:"{0} the limitation, and I {1} it in chapter four. But the design was {2} for depth, not breadth, and the inferences are {3} accordingly.",blanks:[[{en:"I take",ko:"받아들입니다",note:"지적을 담담히 수긍하는 간결체"},{en:"You're right to flag",ko:"지적은 정당합니다",note:"상대의 지적이 옳다고 인정하는 어감"},{en:"I grant",ko:"인정합니다",note:"양보하듯 시인하는 격식 어휘"}],[{en:"foreground",ko:"전면에 내세웁니다",note:"한계를 숨기지 않고 부각한다는 학술어"},{en:"confront",ko:"정면으로 마주합니다",note:"회피 없이 정공법으로 마주한다는 어감"},{en:"don't shy away from",ko:"회피하지 않습니다",note:"꺼리지 않고 직시한다는 표현"}],[{en:"deliberately chosen",ko:"의도적으로 택했습니다",note:"우연 아닌 계획된 선택임을 강조"},{en:"purpose-built",ko:"목적에 맞춰 설계했습니다",note:"특정 목적용으로 맞춤 제작했다는 어감"},{en:"optimized",ko:"최적화했습니다",note:"최적 상태로 다듬었다는 전문어"}],[{en:"hedged",ko:"신중히 한정했습니다",note:"위험 대비로 조심스레 단서를 단 어감"},{en:"scoped",ko:"범위를 좁혔습니다",note:"적용 범위를 한정했다는 표현"},{en:"qualified",ko:"단서를 달았습니다",note:"조건을 붙여 제한했다는 학술어"}]],example:{en:"I take the limitation, and I foreground it in chapter four. But the design was deliberately chosen for depth, not breadth, and the inferences are hedged accordingly.",ko:"그 한계를 받아들이며, 4장에서 전면에 내세웁니다. 다만 이 설계는 넓이가 아니라 깊이를 위해 의도적으로 택한 것이며, 추론은 그에 맞춰 신중히 한정했습니다."}},{prompt:{en:"Be that as it may, what here is genuinely new? Much of this echoes Hartmann's 2019 framework.",ko:"그렇다 쳐도, 여기서 진정으로 새로운 건 뭡니까? 상당 부분이 하르트만의 2019년 틀을 되풀이하는 듯한데요."},template:"Hartmann {0} the terrain, and I'm {1} to him. The {2} is that I show his model {3} under longitudinal data — which he never tested.",blanks:[[{en:"mapped",ko:"윤곽을 그렸고",note:"지형을 그려 보였다는 비유적 표현"},{en:"charted",ko:"지도를 그렸고",note:"체계적으로 도면화했다는 어감"},{en:"broke ground on",ko:"초석을 놓았고",note:"최초로 첫 삽을 떴다는 선구적 어감"}],[{en:"indebted",ko:"빚지고 있습니다",note:"학문적 빚을 졌다는 격식 어휘"},{en:"happy to give credit",ko:"기꺼이 공을 돌립니다",note:"공로를 흔쾌히 인정한다는 어감"},{en:"explicit in my debt",ko:"그 빚을 분명히 밝힙니다",note:"빚을 명시적으로 표기했다는 강조"}],[{en:"departure",ko:"차별점은",note:"기존에서 갈라져 나온 지점을 지칭"},{en:"contribution",ko:"기여는",note:"학계에 더한 공헌을 가리키는 학술어"},{en:"novelty",ko:"독창성은",note:"새로움 자체를 직접 짚는 표현"}],[{en:"breaks down",ko:"무너진다는",note:"기능을 멈추고 무너진다는 어감"},{en:"fails to hold",ko:"성립하지 않는다는",note:"성립 조건을 못 채운다는 학술조"},{en:"comes apart",ko:"허물어진다는",note:"조각조각 흩어진다는 생생한 비유"}]],example:{en:"Hartmann mapped the terrain, and I'm indebted to him. The departure is that I show his model breaks down under longitudinal data — which he never tested.",ko:"하르트만이 지형의 윤곽을 그렸고, 저는 그에게 빚지고 있습니다. 차별점은, 그가 한 번도 검증하지 않은 종단 데이터에서 그의 모형이 무너진다는 것을 제가 보인다는 데 있습니다."}},{prompt:{en:"Your conclusion claims broad policy relevance. Isn't that a reach for a single-country study?",ko:"결론에서 폭넓은 정책적 함의를 주장합니다. 단일 국가 연구로는 무리한 비약 아닙니까?"},template:"{0} — and I'd rather {1} the claim than {2} it. The findings travel as a {3}, not a blueprint, and I say as much.",blanks:[[{en:"Fair challenge",ko:"타당한 지적입니다",note:"반론의 정당성을 깔끔히 인정"},{en:"Point taken",ko:"지적 받아들입니다",note:"수긍을 짧게 표하는 구어 관용구"},{en:"That's a fair pushback",ko:"정당한 반론입니다",note:"반박이 합당함을 풀어 인정하는 어감"}],[{en:"narrow",ko:"좁히는",note:"주장 범위를 줄인다는 기본형"},{en:"temper",ko:"누그러뜨리는",note:"수위를 낮춰 완화한다는 어감"},{en:"rein in",ko:"고삐를 죄는",note:"과한 주장을 당겨 절제한다는 비유"}],[{en:"overstate",ko:"부풀리는",note:"실제보다 크게 말한다는 표현"},{en:"oversell",ko:"과대 포장하는",note:"지나치게 띄워 판다는 어감"},{en:"stretch",ko:"늘려 잡는",note:"근거 너머로 잡아 늘인다는 어감"}],[{en:"hypothesis to test",ko:"검증할 가설로",note:"추후 시험할 가설로 자리매김"},{en:"provocation",ko:"문제 제기로",note:"논의를 촉발하는 화두로 본다는 어감"},{en:"transferable lens",ko:"이전 가능한 렌즈로",note:"다른 맥락에 옮겨 쓸 관점으로 봄"}]],example:{en:"Fair challenge — and I'd rather narrow the claim than overstate it. The findings travel as a hypothesis to test, not a blueprint, and I say as much.",ko:"타당한 지적입니다. 저는 그 주장을 부풀리기보다 좁히는 쪽을 택하겠습니다. 이 결과는 청사진이 아니라 검증할 가설로서 이전되는 것이며, 저도 그렇게 명시합니다."}},{prompt:{en:"Final question: if you had another year, what would you do differently?",ko:"마지막 질문입니다. 1년이 더 있다면, 무엇을 다르게 하겠습니까?"},template:"{0}, I'd {1} the cohort across two more sites to {2} the external validity, and I'd {3} the qualitative coding to a second analyst.",blanks:[[{en:"Honestly",ko:"솔직히",note:"꾸밈없이 본심을 연다는 무난한 도입"},{en:"Without hesitation",ko:"주저 없이",note:"망설임 없이 단호하다는 어감"},{en:"First and foremost",ko:"무엇보다 먼저",note:"최우선 순위임을 강조하는 표현"}],[{en:"broaden",ko:"넓히고",note:"폭을 넓게 키운다는 기본형"},{en:"extend",ko:"확장하고",note:"범위를 더 멀리 뻗는다는 어감"},{en:"replicate",ko:"재현하고",note:"동일 조건으로 다시 검증한다는 학술어"}],[{en:"shore up",ko:"보강하고",note:"약한 곳을 받쳐 튼튼히 한다는 비유"},{en:"stress-test",ko:"엄격히 검증하고",note:"극한 조건으로 시험한다는 전문어"},{en:"firm up",ko:"다지고",note:"단단히 굳혀 확실히 한다는 어감"}],[{en:"assign",ko:"배정하겠습니다",note:"독립 검증 위해 다른 분석가에게 맡긴다는 어감"},{en:"hand off",ko:"넘기겠습니다",note:"다른 사람에게 인계한다는 일상어"},{en:"open up",ko:"개방하겠습니다",note:"외부에 공개해 맡긴다는 어감"}]],example:{en:"Honestly, I'd broaden the cohort across two more sites to shore up the external validity, and I'd assign the qualitative coding to a second analyst.",ko:"솔직히, 외적 타당도를 보강하기 위해 코호트를 두 곳 더 확장하고, 질적 코딩은 두 번째 분석가에게 배정하겠습니다."}}]},{id:"scn-c2-high-stakes-negotiation-001",level:"C2",situation:"high-stakes-negotiation",title:{en:"Closing a high-stakes acquisition",ko:"고위험 인수 협상 타결"},context:{en:"You are negotiating to acquire a rival. The seller anchors high; you challenge the valuation, reframe the risk, bridge the gap, and lock the deal before they walk.",ko:"경쟁사를 인수하기 위해 협상합니다. 매도자가 높은 가격을 제시하고, 당신은 밸류에이션에 이의를 제기하고, 위험을 재구성하고, 간극을 메우고, 그들이 자리를 뜨기 전에 거래를 확정합니다."},turns:[{prompt:{en:"Our number is six hundred million, and frankly we have other suitors circling.",ko:"우리 가격은 6억 달러이고, 솔직히 다른 인수 후보들도 주위를 맴돌고 있습니다."},template:"{0} the interest, but six hundred {1} a multiple the market hasn't paid in years. I'd rather we {2} the number than {3} around it.",blanks:[[{en:"I don't doubt",ko:"의심하지 않습니다",note:"사실로 믿어 준다는 점잖은 인정"},{en:"I respect",ko:"존중합니다",note:"상대 입지를 예우하는 어감"},{en:"I'll take you at your word on",ko:"그 말씀 그대로 믿겠습니다",note:"검증 없이 액면대로 받겠다는 어감"}],[{en:"implies",ko:"전제로 합니다",note:"은연중 그 값을 깔고 있다는 어감"},{en:"bakes in",ko:"내포합니다",note:"이미 가격에 녹아 있다는 구어 관용구"},{en:"assumes",ko:"가정합니다",note:"그렇다고 미리 친다는 중립적 표현"}],[{en:"interrogate",ko:"따져 보는 게",note:"캐묻듯 철저히 심문한다는 강한 어감"},{en:"stress-test",ko:"엄밀히 검증하는 게",note:"극한 가정으로 시험한다는 전문어"},{en:"build up",ko:"쌓아 올리는 게",note:"근거를 차곡차곡 적립한다는 어감"}],[{en:"dance",ko:"빙빙 도는 것보다",note:"핵심을 피해 겉도는 협상 비유"},{en:"skirt",ko:"에둘러 피하는 것보다",note:"본질을 슬쩍 비껴 피한다는 비유"},{en:"tiptoe",ko:"조심스레 도는 것보다",note:"발끝으로 살금살금 피한다는 비유"}]],example:{en:"I don't doubt the interest, but six hundred implies a multiple the market hasn't paid in years. I'd rather we interrogate the number than dance around it.",ko:"관심을 의심하진 않습니다만, 6억은 시장이 수년간 지불한 적 없는 배수를 전제로 합니다. 그 숫자를 빙빙 도는 것보다 함께 따져 보는 편이 낫겠습니다."}},{prompt:{en:"The multiple reflects our growth. Strip that out and you're undervaluing the future.",ko:"그 배수는 우리의 성장을 반영한 겁니다. 그걸 빼면 미래를 과소평가하는 거죠."},template:"Your growth is {0} — but it's also {1} on two contracts that renew next year. {2} that concentration, and the risk-adjusted figure {3}.",blanks:[[{en:"real",ko:"실재합니다",note:"허상 아닌 진짜임을 짧게 인정"},{en:"undeniable",ko:"부정할 수 없습니다",note:"반박 불가일 만큼 확실하다는 강조"},{en:"genuine",ko:"진짜입니다",note:"가짜가 아닌 진정한 것임을 표함"}],[{en:"riding",ko:"기대고 있습니다",note:"그 위에 올라타 의존한다는 어감"},{en:"leaning hard",ko:"크게 의존하고 있습니다",note:"심하게 기대고 있음을 강조"},{en:"perched",ko:"위태롭게 얹혀 있습니다",note:"불안정하게 걸쳐 있다는 위험 암시"}],[{en:"Price in",ko:"반영하면",note:"가격에 위험을 녹여 넣는다는 재무어"},{en:"Factor in",ko:"감안하면",note:"변수로 셈에 넣는다는 일반형"},{en:"Discount for",ko:"할인하면",note:"위험만큼 값을 깎는다는 어감"}],[{en:"tells a different story",ko:"다른 이야기를 합니다",note:"정반대 결론이 나온다는 비유적 표현"},{en:"lands well south of yours",ko:"귀측보다 한참 아래입니다",note:"상대 제시가보다 훨씬 낮음을 강조"},{en:"narrows fast",ko:"빠르게 좁혀집니다",note:"격차가 급격히 줄어든다는 어감"}]],example:{en:"Your growth is real — but it's also riding on two contracts that renew next year. Price in that concentration, and the risk-adjusted figure tells a different story.",ko:"귀측의 성장은 실재합니다. 다만 내년에 갱신되는 두 건의 계약에 기대고 있기도 하죠. 그 편중을 반영하면, 위험 조정 수치는 다른 이야기를 합니다."}},{prompt:{en:"So we're miles apart. I'm not sure this gets done today.",ko:"그럼 우리 사이는 한참 멀군요. 오늘 안에 성사될지 모르겠습니다."},template:"We're closer than it feels. {0} the gap by tying part of the price to those renewals — you {1} the upside if they hold, and I {2} the downside if they don't. {3}?",blanks:[[{en:"Let's bridge",ko:"메워 봅시다",note:"다리를 놓아 잇자는 협상 정착어"},{en:"I can close",ko:"좁힐 수 있습니다",note:"내가 메우겠다는 자신감 있는 어감"},{en:"We split",ko:"나눕시다",note:"차이를 반씩 나눠 갖자는 절충 제안"}],[{en:"keep",ko:"가져가고",note:"이득을 그대로 챙긴다는 기본형"},{en:"capture",ko:"취하고",note:"기회를 붙잡아 거둔다는 어감"},{en:"pocket",ko:"챙기고",note:"주머니에 넣는다는 격의 없는 구어"}],[{en:"absorb",ko:"떠안습니다",note:"손실을 흡수해 받아낸다는 어감"},{en:"carry",ko:"짊어집니다",note:"짐을 진다는 무게감 있는 표현"},{en:"eat",ko:"감수합니다",note:"손해를 그냥 삼킨다는 격의 없는 구어"}],[{en:"Where's the objection",ko:"어디가 걸리십니까",note:"반대 지점을 먼저 캐묻는 적극적 화법"},{en:"Can you live with that",ko:"그 정도면 받아들이실 수 있습니까",note:"수용 가능 여부를 부드럽게 타진"},{en:"Is that workable",ko:"그게 실현 가능합니까",note:"실행 가능성을 사무적으로 확인"}]],example:{en:"We're closer than it feels. Let's bridge the gap by tying part of the price to those renewals — you keep the upside if they hold, and I absorb the downside if they don't. Can you live with that?",ko:"느끼시는 것보다 가깝습니다. 가격의 일부를 그 갱신에 연동해 간극을 메워 봅시다. 계약이 유지되면 그 상승분은 귀측이 가져가고, 무산되면 그 하방은 제가 떠안겠습니다. 그 정도면 받아들이실 수 있습니까?"}},{prompt:{en:"An earn-out... I could sell that to my partners. What would the structure look like?",ko:"언아웃이라... 우리 파트너들을 설득할 수 있겠군요. 구조는 어떻게 됩니까?"},template:"{0}: five-twenty at close, eighty more {1} over two years against the renewals, with {2} so neither side games it — and we {3} exclusivity tonight.",blanks:[[{en:"Keep it clean",ko:"단순하게 가죠",note:"군더더기 없이 깔끔히 가자는 구어"},{en:"Here's the shape",ko:"구조는 이렇습니다",note:"윤곽을 곧장 제시하는 실무 화법"},{en:"Simple as this",ko:"이만큼 단순합니다",note:"더없이 간단함을 강조하는 어감"}],[{en:"earned out",ko:"성과로 지급되며",note:"실적 달성에 따라 지급되는 언아웃 용어"},{en:"released",ko:"풀리며",note:"조건 충족 시 묶인 돈이 풀린다는 어감"},{en:"vesting",ko:"확정되며",note:"기간 경과로 권리가 굳는다는 금융 전문어"}],[{en:"audited milestones",ko:"감사받는 기준을 두어",note:"외부 감사로 검증하는 객관적 기준"},{en:"an agreed formula",ko:"합의된 산식을 두어",note:"양측이 합의한 계산식으로 못 박음"},{en:"clear triggers",ko:"명확한 발동 조건을 두어",note:"지급을 촉발하는 조건을 또렷이 함"}],[{en:"lock in",ko:"확정하겠습니다",note:"못 박아 고정한다는 단단한 어감"},{en:"sign",ko:"체결하겠습니다",note:"서명으로 공식 매듭짓는다는 표현"},{en:"shake on",ko:"악수로 매듭짓겠습니다",note:"악수로 비공식 합의하는 친근한 어감"}]],example:{en:"Keep it clean: five-twenty at close, eighty more earned out over two years against the renewals, with audited milestones so neither side games it — and we lock in exclusivity tonight.",ko:"단순하게 가죠. 클로징 시 5억 2천, 추가 8천만은 갱신 실적에 따라 2년에 걸쳐 성과로 지급되며, 어느 쪽도 장난칠 수 없도록 감사받는 기준을 둡니다. 그리고 오늘 밤 독점 협상권을 확정하겠습니다."}}]}];e.s(["ALL_SCENARIOS",0,o],267976)}]);